INSERT INTO `${schema}` (`id`, `title`, `description`, `free_text`, `lang`, `tags`) VALUES
(196601, 'Führung der Universitätsbibliothek von Le Havre', 'Die 2006 geöffnete Universitätsbibliothek von Le Havre besitzt eine bemerkenswerte Architektur und die an die angebotenen(geschenkten) Dienste besonders angepasst ist.', 'Die 2006 geöffnete Universitätsbibliothek von Le Havre ist das Werk von René und Phine Weeke Dottelonde. Dieser 8000 Quadratmeter Raum ist wie ein lesbarer und geöffneter Ort gedacht worden und ermöglicht, auf die Erwartungen des Publikums, in der Frist(Ende) von Akustik, von Licht und von Raum zu antworten. Die Führung legt den Akzent sowohl auf die privaten(besonderen) Qualitäten dieser Architektur als auch auf die Dienste und die Sitten, die das Gebäude ermöglicht.', 'de', ''),
(196601, 'Visit commented by the university library of Havre', 'Opened in 2006, the university library of Havre possesses a remarkable architecture, and particularly adapted to offered services(departments).', 'Opened in 2006, the university library of Havre is the work of René and Phine Weeke Dottelonde. One thought as a readable(legible) and open place of this 8000-square metre space, and allows to meet the expectations of public, in term of acoustics, of light and of space. Commented visit puts the emphasis both on particular(special) qualities of this architecture and on services(departments) and uses(practices) which allows the building(ship).', 'en', ''),
(196601, 'Visita comentada de la biblioteca universitaria del Havre', 'Abierta en 2006, la biblioteca universitaria del Havre posee una arquitectura notable, y particularmente adaptada a los servicios ofrecidos.', 'Abierta en 2006, la biblioteca universitaria del Havre es la obra de Renacido y Phine Weeke Dottelonde. Este espacio de 8000 metros cuadrado ha sido pensado como un lugar abierto y legible, y permite responder a las esperas de los públicos, en el plazo de acústica, de luz y de espacio. La visita comentada recalca tanto las calidades particulares de esta arquitectura como sobre los servicios y los usos que permite el edificio.', 'es', ''),
(196601, 'Visite commentée de la bibliothèque universitaire du Havre', 'Ouverte en 2006, la bibliothèque universitaire du Havre possède une architecture remarquable, et particulièrement adaptée aux services offerts. ', 'Ouverte en 2006, la bibliothèque universitaire du Havre est l\'oeuvre  de René et Phine Weeke Dottelonde. Cet espace de 8000 mètres carrés a été pensé comme un lieu ouvert et lisible, et permet de répondre aux attentes des publics, en terme d\'acoustique, de lumière et d\'espace. La visite commentée met l\'accent tant sur les qualités particulières de cette architecture que sur les services et les usages que permet le bâtiment.', 'fr', NULL),
(196601, 'La visita(Il soggiorno) ha fatto commenti dalla biblioteca universitaria di Havre', 'Aperto nel 2006, la biblioteca universitaria di Havre possiede un\'architettura notevole, e particolarmente adattato a servizi offerti (i reparti).', 'Aperto nel 2006, la biblioteca universitaria di Havre è il lavoro(opera) di René e Phine Weeke Dottelonde. Un pensiero come un posto(luogo) (leggibile) e aperto piacevole a leggersi(leggibile) di questo spazio di 8000 metri quadrati, e permette di rispondere all\'aspettativa le attese di pubblico, in termine(periodo) d\'acustica, di luce e di spazio. La visita(Il soggiorno) commentata mette l\'accentuazione a qualità sia (speciali)((particolari)) particolari di quest\'architettura sia su servizi (i reparti) e usa (le pratiche) che permette l\'edificio(costruzione) (la nave).', 'it', ''),
(145552, 'Exposition "Une architecture bretonne ?" ', 'Cette exposition interroge "l’acte de construire" en Bretagne.', 'Comment les bâtisseurs de « l’acte de construire » influent-ils sur la production architecturale, urbaine et paysagère d’un territoire ? Faut-il préférer une réponse « internationale » ou une approche « reterritorialisée » à une région et une histoire données, à une culture spécifique ? L’exposition montre l’évolution de la production architecturale en interrogeant autant les réponses formelles que les facteurs qui ont contribué à les faire émerger – ces mécanismes historiques et politiques, économiques et sociétaux actifs depuis les années 80 en Bretagne. Des contributions originales issues de thématiques spécifiques et interprétées à partir de la question posée par le titre de l’exposition sont exposées.', 'fr', ''),
(145553, 'Animation "Lis la façade"', 'jeu éducative', 'Animations pour les classes primaires, du CP au CM2\n\nAprès observation in situ, l''enfant retrouve grâce à un jeu des erreurs les éléments constitutifs de la façade du Palais Granvelle.\n\nLes animations proposées a titre de "Besançon ville d''art et d''histoire" sont réservées exclusivement aux établissements scolaires de Besançon.\n\nVille de Besançon\n\nDirection de Patrimoine Historique\n\nService Transmission Valorisation Médiation\n\nInscriptions par téléphone : 0381615207\n\ncontact : Karine Ménégaux-Doré\n\ncrédit photo : ©mdabesancon', 'fr', 'jeu'),
(145554, 'La Physique du film Interstellar', 'Rencontre entre la physique et un film de science-fiction', 'Les films de science-fiction proposent parfois des visions très pointues de la science et revendiquent une certaine rigueur scientifique. C''est le cas pour « Interstellar » dont le réalisateur Christopher Nolan emporte le spectateur dans un voyage vers les trous noirs.\n\nDans cette conférence, l''astrophysicien Richard Taillet présentera un décryptage scientifique du film pour un public non scientifique et montrera comment les aspects les plus actuels de la science moderne ont joué un rôle dans la conception du film (scénario et effets spéciaux, notamment).', 'fr', 'physique, science-fiction, conférence'),
(145555, 'Microscopie électronique et spectrométrie...', 'Démonstration de microscopie électronique à balayage et analyse élémentaire par spectrométrie EDX', 'La plateforme de microscopié electonique à balayage de l''Institut des Matériaux de Paris Centre (IMPC FR 2482) met à la disposition des laboratoires de recherche de l''UFR de Chimie un microscope électronique à haute résolution équipé d''un spectromètre EDX permettant également d''analyser la composition élémentaire des matériaux.\n\nAu cours d''un visite d''une heure, l''intervenant expliquera le principe de fonctionnement de la microscopie et de l''analyse grâce au faisceau d''électrons et fera une démonstration des capacités de l''appareil sur des échantillons d''origine biologique, minérale et synthétisés par un laboratoire.', 'fr', 'Micrsocopie, Analyse, Electrons, Matériaux, Spectrométrie'),
(145556, 'Vote du Public - Prix Architecture Bretagne 2016', 'Les visiteurs du Salon de l''Immobilier peuvent voter pour leur maison préférée.', 'Dans le cadre du Prix Architecture Bretagne 2016, la MAeB invite le public se rendant au Salon de l’Immobilier de Lorient, à voter pour l’un des 50 projets de maison individuelle présentés cette année.\n\nDes architectes bénévoles de la MAeB seront présents pour accompagner le public dans son choix.', 'fr', ''),
(145557, 'La culture responsable ?', 'Une journée d''échange proposée par ESSAIM 37', 'Depuis 2015, un ensemble d''acteurs culturels et artistiques d''Indre et Loire, tous secteurs et tous corps professionnels confondus, se retrouvent et échangent ensemble. Il s''agit d''ESSAIM, réseau expérimental des métiers Arts & Culture en Touraine.\n\nSouhaitant ouvrir et partager sa réflexion à toutes les parties prenantes du secteur culturel, ESSAIM propose une journée où nous évoquerons l''idée d''une culture responsable. Nous nous poserons ainsi les questions suivantes :\n\n*   Sommes-nous responsables sans culture ?\n*   Qui est responsable de la culture ?\n*   De quoi la culture est-elle responsable ?\n*   La culture doit-elle être responsable ?\n*   Qu''est-ce qu''être responsable en termes de culture ?\n\nDéroulé de la journée :\n\n*   Ateliers participatifs (matin) - Accueil à 9h30 à l’association Jeunesse & Habitat (ex- foyer des jeunes travailleurs) 16 rue Bernard Palissy 37000 Tours.\n*   Déjeuner 13h à l’association Jeunesse & Habitat, 16 rue Bernard Palissy 37000 Tours.\n*   Conférences & Débats (après-midi) - Accueil à 14h à la Auditorium Thélème, Université François Rabelais, 3 rue des Tanneurs 37000 Tours.\n\nPlus d''infos : [www.essaim37.org](http://www.essaim37.org)\n\nRenseignements : [info@essaim37.org](mailto:info@essaim37.org)', 'fr', NULL),
(145558, 'La culture responsable ?', 'Une journée d''échange proposée par ESSAIM 37', 'Depuis 2015, un ensemble d''acteurs culturels et artistiques d''Indre et Loire, tous secteurs et tous corps professionnels confondus, se retrouvent et échangent ensemble. Il s''agit d''ESSAIM, réseau expérimental des métiers Arts & Culture en Touraine.\n\nSouhaitant ouvrir et partager sa réflexion à toutes les parties prenantes du secteur culturel, ESSAIM propose une journée où nous évoquerons l''idée d''une culture responsable. Nous nous poserons ainsi les questions suivantes :\n\n*   Sommes-nous responsables sans culture ?\n*   Qui est responsable de la culture ?\n*   De quoi la culture est-elle responsable ?\n*   La culture doit-elle être responsable ?\n*   Qu''est-ce qu''être responsable en termes de culture ?\n\nDéroulé de la journée :\n\n*   Ateliers participatifs (matin) - Accueil à 9h30 à l’association Jeunesse & Habitat (ex- foyer des jeunes travailleurs) 16 rue Bernard Palissy 37000 Tours.\n*   Déjeuner 13h à l’association Jeunesse & Habitat, 16 rue Bernard Palissy 37000 Tours.\n*   Conférences & Débats (après-midi) - Accueil à 14h à la Auditorium Thélème, Université François Rabelais, 3 rue des Tanneurs 37000 Tours.\n\nPlus d''infos : [www.essaim37.org](http://www.essaim37.org)\n\nRenseignements : [info@essaim37.org](mailto:info@essaim37.org)', 'fr', NULL),
(145559, 'Centenaire Dutilleux 2016 : l''Orchestre français des Jeunes en tournée avec Renaud Capuçon - Young Euro Classic 2016', 'Le concerto pour violoncelle d''Henri Dutilleux sous le signe de la jeunesse, et sous la baguette de David Zinman', '## Programme :\n\n*   Claude Debussy, _Marche écossaise sur un thème populaire_\n*   Henri Dutilleux "Tout un monde lointain..."\n*   Sergei Rachmaninov, _Symphonie_ no3, op. 44\n\n## Avec :\n\n*   Orchestre Français des Jeunes\n*   David Zinman, direction\n*   Gautier Capuçon, violoncelle', 'fr', 'concert,      2016-2017,     symphonique,    orchestre,   Dutilleux,  centenaire, #Dutilleux2016'),
(145560, 'Réaliser ses cartes d''événements : open street map ', 'Comprendre le projet OpenStreetMap, ses possibilités et ses usages les plus courants', '**Le projet OpenStreetMap, usages et outils**\n\nLe projet OpenStreetMap et ses usages : tourisme, transport, accessibilité, humanitaire ...  \nUtiliser pleinement le site [www.openstreetmap.org](http://www.openstreetmap.org)  \nImprimer une carte  \nLes meilleurs sites et applications de l''écosystème OpenStreetMap\n\n**Réaliser une carte interactive avec umap**\n\nRéaliser une carte umap, la diffuser par email ou l''intégrer dans un site Web  \nRépartir les éléments de la carte dans plusieurs calques  \nStyliser la carte, intégrer photos et liens vers des pages Web  \nGéocoder un fichier contenant des adresses et l''importer dans umap  \nCalculer un itinéraire et l''intégrer à une carte umap\n\n**Chercher des données dans OpenStreetMap, améliorer la carte**\n\nComprendre les données OpenStreetMap  \nChercher et extraire des données (ex: commerces d''une commune)  \nModifier la carte OpenStreetMap : créer une note, ajouter un commerce  \nPour aller plus loin : communauté, forums, tutoriels ...\n\n[S''inscrire ](http://www.assomediagraph.fr/contact/)', 'fr', 'Open street map, cartes'),
(145561, 'Exposition "L''architecture des bâtiments ruraux de la région du Fujian (Chine)"', 'Restitution d''un workshop commun aux étudiants de master de l''Ecole nationale supérieure d''architecture de Saint-Etienne (ENSASE) et de l''East China Normal University de Shanghai (ECNU)', '**A la découverte de l’architecture des grands bâtiments ruraux de la région Taixi dans le Fujian (Chine)**\n\nEXPOSITION\n\nLes étudiants de l’ENSA Saint-Etienne et de l’ECNU (East China Normal University) de Shanghai, ont étudié pour la première fois des bâtiments particuliers entre ferme, maison forte et maison de la famille, issus de l’art de bâtir de l’ancienne Chine. Feng Shui, art de construire, conception du paysage, ventilation naturelle, sacré et profane, symboles et pragmatisme de la ruralité : entre sophistication et simplicité ces bâtiments présentent une cosmogonie où vivants et morts s’inscrivent à travers une architecture.\n\nLes projets, réalisés par les étudiants, ouvrent d’autres possibilités afin d’éviter le « mutisme » de la Chine sur la potentialité de son passé et pour vivre le village aujourd’hui. Ces projets s ‘inscrivent dans le cadre d''une recherche académique pilotée par l’ECNU (Dir. Shaonong WEI) faisant l’objet de forum et publications.\n\n**Enseignants :** Romain CHAZALON & Claude TAUTEL et la participation de Hongqing JIANG et de Clifford PEARSON (Univ. of Southern California) ainsi que de avec Florian KLEINEFENN, photographe.\n\n**Étudiants de master du domaine Architecture Urbanisme Territoires ** : Marine BORDAT, Anne-Laure BOURRAT, Ines FEKIH, Julien GERARD, Sandrine HEROUX, Héloïse JAMET, Olivier LE GALL, Tedwin LE GUERNIC, Caroline NGUYEN, Clara RIOU-BÉNARD.\n\nAvec le soutien financier de la Région Auvergne Rhône Alpes', 'fr', 'Chine, Architecture, Urbanisme, Patrimoine, Rénovation, Saint-Etienne, ruralité'),
(145562, 'Centenaire Dutilleux 2016 : l''Orchestre français des Jeunes en tournée avec Renaud Capuçon - Festival de Laon (Aisne)', 'Le concerto pour violoncelle d''Henri Dutilleux sous le signe de la jeunesse, et sous la baguette de David Zinman', '## 28e Festival de musique française de Laon\n\nL’avant-dernier ouvrage de Rachmaninov précédant les ultimes _Danses symphoniques_. Un immense orchestre et un condensé du style final du compositeur, mixant certaines imprégnations de l’Amérique où il émigra et un profond enracinement dans sa culture russe.\n\nAux côtés de cette œuvre postromantique du XXème siècle, le "classique" concerto pour violoncelle de Dutilleux, créé par Rostropovitch en 1970 au Festival d’Aix-en-Provence. Inspiré des _Fleurs du mal_, le traitement de l’instrument soliste tel un « médium entre l’univers de Baudelaire et le monde sonore, pour tout ce qui s’identifie à l’idée d’évasion ». Une page d’exception lumineuse et lyrique, pour le centenaire du compositeur.\n\n## Programme :\n\n*   Sergei Rachmaninov, _Symphonie_ no3, en la mineur, op. 4\n*   Henri Dutilleux "Tout un monde lointain..."4\n\n## Avec :\n\n*   Orchestre Français des Jeunes\n*   David Zinman, direction\n*   Gautier Capuçon, violoncelle', 'fr', 'concert,       2016-2017,      symphonique,     orchestre,    Dutilleux,   centenaire,  #Dutilleux2016, festival'),
(145563, 'Meetup e-santé #1 - Soirée dédiée aux biomédicaments', 'Meetup e-santé #1 - Soirée dédiée aux biomédicaments', 'Voilà un mot qu''on entend de plus en plus souvent mais dont la signification reste floue pour la plupart d''entre nous. Et pourtant, les biomédicaments nous concernent de près...\n\nIl se trouve que la Touraine est à la pointe sur cette question. Parmi les acteurs qui compte : l''[IMT](http://www.groupe-imt.com/) qui a notamment en charge la direction du [Bio3Institute](http://bio3institute.fr/). Joan Leclerc, chargé de mission ARD Biomédicaments au sein du [Groupe IMT](http://www.groupe-imt.com/), viendra à notre rencontre pour éclairer notre lanterne le temps d''une soirée sous le signe de la convivialité qui se conclura par un buffet offert par la société [Vermon](http://www.vermon.com/vermon/) !', 'fr', 'biomedicaments, meetup, e-sante'),
(145564, 'Bertrand de Billy dirige le Konzerthausorchester Berlin dans "Le Double"', 'La deuxième symphonie d''Henri Dutilleux à Berlin, Isabelle Faust au violon pour le 2e concerto de Bartok', '## Programme :\n\n*   Henri Dutilleux _Symphonie_ No.2 ("Le double")\n*   Béla Bartók _Concerto pour violon et orchestre_ No. 2\n*   Maurice Ravel _La Valse_ - Poème chorégraphique pour orchestre\n\n## Avec :\n\n*   Konzerthausorchester Berlin\n*   Bertrand de Billy, direction\n*   Isabelle Faust, violon', 'fr', 'concert, 2016-2017, Dutilleux, centenaire, Berlin, symphonie, orchestre, Ravel'),
(145565, 'Visite architecturale "A la découverte de Notre-Dame-du-Haut"', 'visite artistique et culturelle', 'Pendant plus de deux heures les 25 collégiens de 3e du  Collège Lucie Aubrac seront accompagnés par  Karine Terral architecte conseiller au CAUE du Doubs pour découvrir la colline et plus particulièrement la chapelle de Notre-Dame-du-Haut. Seront abordés le rapport au site, les péripéties de la commande, le comment ça tient, pour finir sur l''esthétique et les émotions que cette architecture suscite.\n\nCette visite s''inscrit  dans le cadre du projet artistique et culturel « Habitat durable »  accompagné par le CAUE tout le long de l''année avec vendredi 14 octobre une journée spéciale sur la découverte de Le Corbusier, le matin étant consacré à son "cabanon".', 'fr', ', visite'),
(145566, 'Le retour de MoiChef à Toulouse', 'https://www.eventbrite.com/e/moichef-notre-retour-a-toulouse-tickets-27758088189', NULL, 'en', ',   startup,  foodtech,  '),
(145567, 'Apéro entrepreneurs', 'https://www.meetup.com/fr-FR/StartupEvening/events/233680280/', NULL, 'en', NULL),
(145568, 'Participez à la rentrée de PAVIC - Angers Smart City Platform', 'Présentation des Projets et nouvelles Actions | Saison 2016-2017', 'Pour cela nous comptons sur votre présence le JEUDI 6 OCTOBRE 2016 à partir de 17h pour la réunion de la rentrée 2016 – 2017 de notre plateforme d''expérimentation qui sera à la fois l''occasion de vous présenter les objectifs de l''année à venir, mais aussi de consolider notre réseau des acteurs de la Smart City.\n\nVous pourrez durant cette réunion découvrir les projets qui sont déjà en cours de réalisation grâce à nos intervenants, rencontrer nos nouveaux adhérents et pourquoi pas tisser ensemble notre vision.\n\n[Le nombre de place était limité, nous vous prions de bien vouloir vous inscrire sur la plateforme eventbrite](https://www.eventbrite.fr/e/billets-pavic-angers-smart-city-platform-la-rentree-2016-2017-27925177959?aff=es2).', 'fr', ',        expérimentations,       Smart City,      IoT,     Angers ville test,    Angers,   Angers French Tech,  PAVIC, Angers Smart City Plateform'),
(145569, 'Un musée, une architecture', 'De l’Hôtel Julia au nouveau Musée de Pont-Aven, créé par l’équipe du cabinet d’architectes de l’Atelier de l’Ile, venez découvrir les anecdotes de ce grand chantier qui a duré près de trois ans.', 'Musée de Pont-Aven : « Un nouveau musée, une architecture inédite »\n\nLe service des publics propose une visite insolite centrée sur l’architecture du nouveau musée et son histoire. De l’ancienne annexe de l’Hôtel Julia au nouveau Musée de Pont-Aven, créé par le cabinet d’architectes l’Atelier de l’Ile (auteurs notamment de la réhabilitation du Pavillon Amont au Musée d’Orsay et de la nouvelle muséographie du Musée Rodin), découvrez les anecdotes de ce grand chantier qui a duré près de trois ans (2013-2016).\n\nVendredi 14 octobre : de 11h à 12h. Visite avec Stéphanie Derrien, médiatrice culturelle et de Marc Quélen, architecte du nouveau Musée de Pont-Aven, agence L’Atelier de l’Ile.\n\nSamedi 15 octobre : de 14h30 à 15h30\\. Visite avec une médiatrice culturelle du Musée de Pont-Aven.\n\nDimanche 16 octobre : de 14h30 à 15h30\\. Visite avec une médiatrice culturelle du Musée de Pont-Aven.', 'fr', 'hôtel, musée, pont-aven, architecte, ile, chantier'),
(145570, 'Musée de la Pêche : les secrets des bâtiments', 'Découvrez les secrets des bâtiments qui abritent aujourd’hui le musée.', 'Musée de la Pêche : les secrets des bâtiments\n\nDe la chapelle Notre-Dame-du-Rosaire en passant par la Caserne Hervo, le service des publics vous invite à découvrir, pendant 45 minutes, les secrets des bâtiments qui abritent aujourd’hui le musée.\n\nAccompagné par une médiatrice, parcourez les salles du musée et, à l’aide de photographies d’archives, reconstituez l’évolution des lieux.\n\nVendredi 14 octobre : 11h et 15h\n\nEntrée au musée : Tarif plein : 5 € et tarif réduit : 3€, gratuit pour les moins de 18 ans, médiation gratuite. Réservation conseillée au 02.98.97.10.20.\n\n25 personnes maximum.', 'fr', 'secrets, bâtiments, musée, pêche, caserne'),
(145571, 'PORTES OUVERTES FRONSAC - CANON FRONSAC', 'les châteaux du Fronsadais vous ouvrent leurs portes de 10h à 18h00 et vous invitent à découvrir leur derniers millésimes.', '## 30 CHÂTEAUX VOUS OUVRENT LES PORTES DE LEURS CHAIS DE 10H00 A 18H00\n\n## MAISON DES VINS DE FRONSAC\n\n*   initiation à la dégustation avec un animateur de l''Ecole du Vin de Bordeaux toutes les 1/2 heures de 10h00 à 12h30 et de 14h00 à 18h00 le samedi et dimanche (groupe de 30 personnes - gratuit)\n*   petit train touristique, découverte commentée des vignobles de Fronsac- départ de la Maison des Vins de Fronsac - gratuit\n*   trail des coteaux de Fronsac - le dimanche - course de 10km  et 12 km inscriptions et renseignements sur \n\n    [www.traildescoteauxdefronsac.com](http://www.traildescoteauxdefronsac.com/)\n\n## ANIMATIONS DANS LES CHATEAUX\n\n*   **Château Canon St Michel 06.08.33.81.11** : séance d’initiation à la dégustation, accord mets et vin animé par l''oeologue Marc Quertinier - exposition de pastel - dimanche: balade en calèche\n*   **Château Cassagne Haut Canon 06.23.111.439** exposants divers :chocolat, fromages...\n*   **Château Coustolle 05.57.51.31.25** dimanche après midi: animation musicale\n*   **Château de La Rivière 05.57.55.56.56 **vente de produits du terroir, safran, animations diverse, visite de 8hectares de caves souterraines.\n*   **Château Franc Capet 06.03.56.25.27** vente de miel direct du producteur\n*   **Château Gaby** **05.57.51.24.97 **exposition de toiles, ateliers oenologiques, démonstration de traction animale, exposition de voitures anciennes\n*   **Château Haut-Peychez 06.77.74.22.20 **exposition de peinture Rosemonde Gouzille\n*   **Château La Grave 05.57.51.31.11 **vente de lamproie de Stephane Malgat sur place et/ou à emporter\n*   **Château Labory 06.84.17.55.32** dégustation fromage de chèvre\n*   **Château Lambert 05.57.24.98.51** exposition de sculptures de M Merc Louvel et abats jour crée par Isabelle Rigaud\n*   **Château Roumagnac La Maréchale 06.88.85.91.38 **Exposition de Margret Nigen, objets de décoration et de l''art de la table\n*   **Château Saint Vincent 06.13.37.05.53 **Animation enfant dimanche 15h00 et 16h30: Mme Saperlipopette raconte "promenons-nous dans les vignes". - exposition des oeuvre de Christian Massé, artisan d''art, peinture sur supports naturels( ardoise, écorces, tuiles...) - déustation des vieux millésimes 1980 et 1990.\n*   **Château Steval 06.13.80.33.62 **animation musicale celtique "Le Bagdad Des Abers" - fromager des pyrénées - exposition de peintures\n*   **Château Tasta 05.57.24.97.62** Minoterie Boiron avec ses farines\n*   **Le Pavillon de Fronsac vignobles Ponty 05.57.51.29.57 **exceptionnelle dégustation de très vieux millésimes de la cave privée du Château\n*   **Union de Producteurs de Lugon - les vignerons du Fronsadais 05.57.55.00.88 **Exposition artisans, visites de chais et dégustations gratuites - nombreuses promotions\n\n## RESTAURATION\n\n### Samedi 22 Octobre _le midi_\n\n*   **Château Arnauton** (sur réservation avant le 19.10 au 06.33.11.79.55)\n\n12€ (entrée, jambon braisé, dessert)\n\n*   **Château Barrabaque  06.07.46.08.08**\n\n16€ (poulet fermier, frites, fromage, café gourmand) accompagné des vins de la propriété.\n\n*   **Château Canon Saint Michel** (sur réservation 06.59.49.89.20)\n\nmenu champêtre 12€ - menu du terroir 15€ - assiettes d''huîtres\n\n*   **Château de la Rivière  réservation conseillée (nombre de places limitées) 05.57.55.56.56**\n\nMenu19€ (foie gras, magret, desssert, vin)\n\n*   **Château Haut-Peychez 06.77.74.22.20**\n\nrepas "pot au feu des vendanges"\n\n*   **Château La Valade 06.98.25.27.08**\n\nRepas et musique\n\n*   **Château Magondeau 05.57.84.32.02**\n\ndégustation d''huîtres, roblochon, comté et escargots\n\n*   **Château Maroy 06.62.47.98.93**\n\ndéjeuner champêtre 13€ (entrée unique, plat au choix: axoa de veau - boeuf bourguignon au vin - jambon braisé - dessert)\n\n*   **Château Steval réservation obligatoire 06.13.80.33.62**\n\nrepas proposé dans le nouveau chai \n\nmenu du terroir 16€ (salade de gésiers ou saumon mariné, pièce de bœuf ou magret de canard, fromage, dessert) un verre de vin est offert\n\n###  Samedi 22 Octobre _le soir_\n\n*   **Château Cassagne Haut-Canon sur réservation 06.23.111.439**\n\nconcert dinatoire à 19h30 "musique à ta porte"(orchestre contemporain du monde) 30€\n\n*   **Château La Valade 06.98.25.27.08**\n\nRepas et musique\n\n*   **salle des fête Saillans 05.57.24.98.51**\n\nChâteau Saint Vincent & Château Lambert organisent un dîner/show cabaret.\n\nRepas d''inspiration antillaise et show cabaret par la compagnie Lez''arts qui courent.\n\n27€ : accras de morue, colombo de poulet, riz jonjon, fromage, glace coco et dégustation de différents vins du Château St Vincent et Château Lambert\n\n*   **Château Steval réservation obligatoire 06.13.80.33.62**\n\nmenu de la mer 16€ (assiette de la mer: bigorneaux, crabe, huîtres; choucroute de la mer; far breton) un verre de vin est offert\n\n### Dimanche 23 Octobre _le midi_\n\n*   **Château Arnauton** (sur réservation avant le 19.10 au 06.33.11.79.55)\n\n12€ (entrée, entrecôte, frites, dessert)\n\n*   **Château Barrabaque**  06.07.46.08.08\n\n16€ (poulet fermier, frites, fromage, café gourmand) accompagné des vins de la propriété.\n\n*   **Château Canon Saint Michel** (sur réservation 06.59.49.89.20)\n\nmenu champêtre 12€ - menu du terroir 15€ - assiettes d''huîtres\n\n*   **Château Cassagne Haut-Canon** sur réservation 06.23.111.439\n\nrestauration champêtre autour de 15€\n\n*   **Château de la Rivière  réservation conseillée (nombre de places limitées) 05.57.55.56.56**\n\nMenu19€ (foie gras, magret, desssert, vin)\n\n*   **Château La Valade 06.98.25.27.08**\n\nRepas et musique\n\n*   **Château Magondeau 05.57.84.32.02**\n\ndégustation d''huîtres, roblochon, comté et escargots\n\n*   **Château Maroy 06.62.47.98.93**\n\ndéjeuner champêtre 13€ (entrée unique, plat au choix: axoa de veau - boeuf bourguignon au vin - jambon braisé - dessert)\n\n*   **Château Roumagnac la Maréchale 05.57.24.94.55 ou 06.88.85.91.38**\n\nrepas champêtre \n\n*   **Château Steval réservation obligatoire  06.13.80.33.62**\n\nrepas proposé dans le nouveau chai \n\nmenu du terroir 16€ (salade de gésiers ou saumon mariné, pièce de bœuf ou magret de canard, fromage, dessert) un verre de vin est offert\n\n*   **Union des producteurs de Lugon - les vignerons du Fronsadais 05.57.55.00.88**\n\nrestauration sur place sous chapitaux, produits du terroir. Composez votre repas et partagez un moment convivial avec les producteurs artisans.', 'fr', NULL),
(145572, 'Journée de la transition', 'Moment festif utour des initiatives citoyennes autour de Châteauneuf sur Loire  le 1er octobre ', 'Chaque année depuis 2014 l''association "Châteauneuf sur Loire en Transition" organise sa journée de la transition sous la halle de la ville. Repas partagé le midi, mini conférences, rencontres, économie solidaire et sociale.\n\nBienvenue à toutes et tous', 'fr', 'développement durable, monnaie locale complémentaire, agriculture paysanne, énergies renouvelables, sel, cre-sol'),
(145573, 'ATELIERS DE FLÛTE MANDINGUE AVEC DRAMANE DEMBÉLÉ', 'Dans le cadre d’une résidence de création d’artistes, Dramane Dembélé proposera des ateliers d’initiation à la technique traditionnelle de la flûte mandingue à la Maison Populaire.', 'Né en Côte d’Ivoire Dramane Dembélé dit “ Djomakossa” a passé son enfance au Burkina Fasso. Il est la révélation des jeunes flûtistes burkinabés. Issu d’une famille de griots, maîtres de l’oralité, Dramane Dembélé poursuit cette tradition en transmettant par sa musique tout ce qui a trait aux louanges et aux réconciliations.Là où il passe, il partage cette fierté comme l’ont fait, avant lui, son père et ses ancêtres.Dramane s’inspire d’événements quotidiens de la société urbaine vus au travers du prisme de l’éducation qu’il a reçue de ses parents et de ses frères pour vous faire voyager\n\nTalentueux musicien et auteur-compositeur, il a joué auprès de grands artistes africains, chanteurs, conteurs, acteurs comme Solo Dja Kabak, Abaca Adam Abaye, François Dembélé, Sotigui Kouyaté, et a participé à de nombreux festivals dans différents pays d’Afrique et à travers le monde.\n\nAteliers d’initiation à la flûte mandingue :\n\n*   Deux ateliers de 3 heures : samedi 12 novembre de 16h30 à 19h30 et samedi 19 novembre de 16h30 à 19h30 suivi d’une restitution publique de 20h à 21h\n*   Le public : des flûtistes de tous types ayant au minimum deux ans de pratique\n*   Les ateliers sont gratuits et sur réservation\n*   Le nombre de place est limité à 10 participants\n\nInscription et réservation à la Maison Populaire au 01.42.87.08.68 ou sur place à l’accueil.\n\nMaison Populaire\n\n9 bis rue Dombasle, 93100 Montreuil\n\n[Vidéo de Dramane Dembélé - Flûte peule // Cliquez ici](https://www.youtube.com/watch?v=4WqfF9s2OBI)', 'fr', ',     Dramane Dembélé,     flûte,    mandingue,   atelier,  '),
(145574, 'Parcours multimédia "Limoges, quartier de la Boucherie"', 'Le parcours multimédia "Limoges, quartier de la Boucherie" vous invite à découvrir ce quartier ancien et pittoresque du centre ville, aux ruelles piétonnes bordées de maisons à pans de bois.', 'Cette balade urbaine est ponctuée de 12 étapes expliquées par des séquences documentaires vidéos ou audio, parmi lesquelles vous pourrez notamment découvrir les halles centrales à l''architecture d''inspiration Eiffel, la place de la Barreyrette, la chapelle Saint-Aurélien, les maisons à pan de bois et les anciennes boutiques de bouchers situées au rez-de chaussée de ces dernières.\n\nPour pouvoir suivre le parcours, connectez en wi-fi votre appareil mobile (smartphone ou tablette) et téléchargez l''application mobile gratuite Vidéoguide Limousin, puis le parcours Limoges quartier de la Boucherie. Rendez-vous sur Google Play ou Apple store, ou suivez simplement le lien de téléchargement : [http://apps.camineo.com/limousin/main.html](http://apps.camineo.com/limousin/main.html)\n\nUne fois le parcours téléchargé, plus besoin de se connecter au réseau. Tous les contenus multimédias et les cartes sont embarqués dans votre appareil. Vous n''avez plus qu''à vous laisser guider par le GPS intégré, écouter les commentaires et regarder les vidéos.\n\nSi vous ne pouvez pas vous déplacer, vous pouvez également consulter l''intégralité des contenus multimédias depuis chez vous, sur votre ordinateur, en vous connectant sur videoguidelimousin.fr\n\nhttp://www.videoguidelimousin.fr/parcours/quartier-de-la-boucherie\n\nL''intégralité des contenus est aussi disponible en langue anglaise.', 'fr', 'Limoges,  chapelle,  pan de bois, Boucherie'),
(145575, 'Bistrot du Boss club chez Cinéphase', 'Le Bistrot du Boss Club PME se déplace à Vanves ce mois-ci pour la visite de l''entreprise CINEPHASE', 'L''entreprise vanvéenne CINEPHASE ouvrira ses portes pour découvrir le monde magique et très technique de la post production, du doublage au mixage en passant par le bruitage.\n\nLe bistrot du Boss club sera également l''occasion d''assister à une présentation d''Eric Mathivet, président de l''agence éditoriale sur web Mativox sur les bons choix à prendre dans l''utilisation d''Internet pour trouver des clients. Editeur et auteur depuis 25 ans, Eric Mathivet a suivi l''évolution d''Internet, des débuts du référencement naturel à la déferlante actuelle des contenus. Il a adapté son savoir-faire éditorial aux nouvelles stratégies de webmarketing et aide les entreprises à attirer de nouveaux prospects.\n\n*   [Site web du Boss Club PME](http://www.boss-club.net/accueil/)\n*   [Site web de CINEPHASE](http://cinephase.com/fr/home/)\n*   [Site web de l''agence MATIVOX](http://www.mativox.fr/)', 'fr', 'Boss Club, Vanves, Cinephase'),
(145576, 'L''atmosphère: des moyens de mesures à la recherche en passant par la prévision météorologique.', 'Le Lacy (Laboratoire de l''Atmosphère et des CYclones) et Météo-France s''associent pour vous faire découvrir leurs activités.', 'Météo-France et le Lacy (Laboratoire de l''Atmosphère et des Cyclones) s''associent sur un vaste stand de la fête de la science pour vous faire découvrir leurs activités et leurs métiers. Trois modules thématiques sont présentés au public: les mesures des paramètres atmosphériques (stations automatiques, ballons-sondes, imagerie satellitale ...), la prévision cyclonique et la recherche météorologique. Conférences, mises en situation et nombreuses expériences interactives sont proposées au public quelque soit son âge.', 'fr', ',            METEO-FRANCE,            UNIVERSITE,           Atmosphère,          recherche,        prévision,       mesures,      expériences,     cyclones,    ballons,    satellites,   météorologie, modèles'),
(145577, 'The Global Grid, le réseau d’électricité mondialisé ?', 'RTE invite Damien Ernst, Professeur à l’Université de Liège, à présenter sa vision du « Global Grid » et échanger sur la fonction que les réseaux de transport d’électricité joueront dans le futur.', 'Avec la transition énergétique et le développement rapide des énergies renouvelables, le rôle des grands réseaux d’électricité est réexaminé entre applications territoriales et système électrique européen.\n\nDans le cadre de la Fête de la Science, RTE invite Damien Ernst, Professeur à l’Université de Liège et titulaire de la chaire EDF Luminus sur les Smart grids, à présenter sa vision du « Global Grid » et échanger sur la fonction que les réseaux de transport d’électricité joueront dans le futur.\n\n**Déroulement de la conférence**\n\n*   Introduction de la conférence par Michel Bena, Directeur Smart grids, Direction R&D-I, RTE\n*   Présentation interactive du concept de « Global Grid » par Damien Ernst, Professeur à l’Université de Liège\n*   Discussion entre Michel Bena et Damien Ernst sur les perspectives d’évolution des grands réseaux d’électricité\n*   Echanges et questions/réponses avec la salle\n\n[En savoir plus sur RTE](http://www.rte-france.com)', 'fr', 'transition énergétique, réseau de transport d''électricité, smart grids, global grid, prospective'),
(145578, 'Réunion du groupe 4', 'Le musée comme écosystème professionnel créatif', NULL, 'fr', ', réunion'),
(145579, 'Portes ouvertes "Conseils gratuits" ', ' Vous avez un projet! Un architecte vous reçoit pour vous guider et vous conseiller dans une démarche de projet.', 'Vous souhaitez construire, rénover, agrandir, réhabiliter...\n\nLe CAUE VAR met en place des permanences le jeudi 13 et vendredi 14 octobre 2016 de 10h à 16h.\n\nUn architecte vous recevra pour vous guider et vous conseiller sur votre projet de construction, réhabilitation, rénovation, extension.\n\nPrise de rendez-vous obligatoire au 04 94 22 65 75.', 'fr', 'architecture, conseils'),
(145580, 'Cap International', 'La Banque Populaire des Alpes organise un évènement unique destiné aux chefs d’entreprise qui souhaitent se développer à l’international. ', 'Le jeudi 6 octobre 2016, au World Trade Center de Grenoble, la Banque Populaire des Alpes propose aux chefs d''entreprise une journée thématique autour de l''international. Différentes rencontres sous forme d’ateliers thématiques, d’entretiens individuels se dérouleront tout au long de la journée.\n\nMarchés, territoires, financements, réseaux et négociation sont des enjeux incontournables pour croître à l’international. Dès lors, quelles stratégies adopter pour s’imposer loin de ses bases ? Ce sont toutes les questions abordées lors de la conférence « Le choix de l''international ».\n\nAvec les témoignages de :\n\n• Thierry de La Tour d’Artaise, Président Directeur Général du Groupe SEB\n\n• Jacques Lacroix, Président Directeur Général de Maped\n\n• Pascal Mauberger, Président Directeur Général de McPhy Energy SA\n\n• Boris Saragaglia, Président Directeur Général de Spartoo SAS', 'fr', NULL),
(145581, 'Exposition "22 Envies d’Architecture : réalisations varoises, contemporaines, durables"', 'Exposition', 'Le CAUE VAR avec la collaboration du Conseil général du Var et du Syndicat des architectes du Var, propose l’exposition «22 Envies d’Architecture : réalisations varoises, contemporaines, durables.» dans ses locaux à Toulon.\n\nIl s’agit de promouvoir une architecture pour tous, de qualité, répondant aux problématiques environnementales, économiques et sociales d’aujourd’hui et de demain. Elle révèle au public des réalisations contribuant à la richesse de nos territoires varois.\n\nCette exposition non exhaustive présente 22 réalisations récentes actant des progrès en matière de construction et de l’évolution des lignes architecturales dans une approche développement durable. Pour rappel, la part du bâtiment représente 40% des dépenses énergétiques en France.', 'fr', 'architecture, développement durable, architecture méditerranéenne durable, caue var'),
(145582, 'Festival des Orgues du Pays Loire-Beauce', 'Concert d''Alès BARTA à l''orgue', NULL, 'fr', NULL),
(145583, 'Soon Hot and Sunny', 'dans le cadre du festival Bar-Bars', 'Trio de covers, des années 60 à aujourd''hui, à la sauce Folk, Swing, Surf & Vintage...\n\nSoon Hot And Sunny (SHAS) est né d''une rencontre des trois musiciens de la scène Angevine. La forme est simple : Une guitare, des percussions et une voix qui nous plonge dans l''univers de la Pop à travers des Covers (Reprises) ré-arrangées par leurs soins. Fraicheur et tubes à l’appui…\n\n[https://www.youtube.com/watch?v=OU-d462qTnc](https://www.youtube.com/watch?v=OU-d462qTnc)', 'fr', 'Reprises des années 60 à nos jours'),
(145584, 'Cartographie ren@rde', 'A travers trois expositions et un festival, « Cartographie ren@rde » cherche à comprendre l’évolution récente des processus identitaires par le prisme de l’art contemporain.', 'Projet collectif, _Cartographie ren@rde_ est inspiré des réflexions théoriques menées par Paul (Beatriz) Preciado : une interrogation sur l’évolution récente des processus identitaires contemporains, opposant au sein des pratiques culturelles et artistiques deux formes de stratégies politiques. La première, dite « du lion », vise à normaliser les identités, dans un grand récit linéaire lié à la modernité. La seconde, dite « du renard », réaffirme les singularités irréductibles des identités, issues d’un croisement complexe entre territoires, cultures et trajectoires individuelles. Une « cartographie renarde » se constitue, de milliers de récits qui se croisent, s’opposent, se répondent, jouent et attestent aussi d’un grand basculement : l’irruption des nouvelles technologies, les sciences du vivant et la réduction inéluctable de la biodiversité.\n\nLe projet _Cartographie ren@rde_ cherche à voir, comprendre et analyser ce champ appliqué à l’art contemporain. Il propose trois expositions, un festival et quatre modes d’interrogations : chaque lieu s’intéressant plus particulièrement à un ensemble d’œuvres ou à un thème.\n\nLe _Centre d’art Transpalette_ se propose de construire une exposition plus historique (de 1977 à nos jours). Il présente une sélection d’œuvres historiques et récentes — dessins, photographies, installations, vidéos, performances et traces de performances — issues à la fois des collections du Centre Pompidou et de collections privées : Gina Pane, Pipilotti Rist, Anne-Marie Schneider, William Burroughs, John Giorno, Derek Jarman, Michel Journiac, Paul McCarthy, Bruce Nauman, Natacha Nisic et plus de dix autres artistes.\n\nLes _Rencontres Bandits-Mages_ répondent par une mise en jeu de la « cartographie ren@rde » à travers la fabrication collective d’un espace d’exposition, de performance et de projection d’objets vidéos et cinématographiques issus des collections du Centre Pompidou et d’autres institutions françaises et internationales.\n\nQuant à _La Box de l’Ensa_, elle choisit de présenter une œuvre emblématique des collections du Centre Pompidou liée à cette thématique.\n\nÀ travers un programme de performances et d’interventions, le _49 Nord 6 Est – Frac Lorraine_ tente de voir comment le champ du post-porn enrichit ce débat.', 'fr', NULL),
(145585, 'Lumières sur l''astronomie', 'Un éclairage sur l''application de la démarche scientifique, le rôle des femmes et l''utilisation de la lumière dans le domaine de l''astronomie', 'Accueil du grand public tout au long de la journée au travers des cinq ateliers suivants :\n\n*   Planétarium numérique : séance destinée à illustrer au travers d''exemples concrets l''application de la démarche scientifique à l''astronomie\n*   L''astronomie au féminin : présentation et illustration au travers de cas concrets du rôle joué par les femmes à travers les âges dans le domaine de l''astronomie\n*   Comment faire parler la lumière des étoiles : présentation des possibilités offertes par la spectroscopie pour l''analyse de la lumière des étoiles, et illustration par une expérience pratique\n*   La lumière de notre étoile, le Soleil : observation du Soleil en lumière visible et dans la raie Halpha d''émission de l''hydrogène au moyen d''instruments astronomiques (atelier remplacé par une présentation du rôle des comètes et de la mission ROSETTA en cas de conditions météorologiques défavorables)\n*   Atmosphère et propagation de la lumière : présentation des différentes perturbations introduites par notre atmosphère dans la propagation de la lumière au travers de différentes expériences pratiques s''appuyant sur le phénomène de l''arc-en-ciel\n\nEn complément de ces ateliers, différentes expositions réalisées par le Laboratoire d''Astrophysique de Marseille seront disponibles en accès libre.', 'fr', 'astronomie, spectroscopie, planétarium'),
(145586, 'Les dimensions dans l''Univers', 'Conférence prononcée par Fabrice FEINSTEIN, professeur à l''Université de Montpellier 2 et chercheur au Centre de Physique des Particules de Marseille', 'Les distances qui nous séparent des objets célestes sont tellement vastes qu’il est très difficile de les mesurer et de se représenter correctement leur grandeur. Le conférencier exposera comment les Grecs Anciens ont estimé notre distance à la Lune, et comment les astronomes modernes ont mesuré la taille du système solaire, puis estimé notre distance aux étoiles. Petit à petit, l’astronomie a observé des objets de plus en plus lointains. Il expliquera également quelles techniques modernes utilisent les télescopes actuels comme le satellite Gaia et le Large Synoptic  Survey telescope, et font avancer notre compréhension de l''Univers.', 'fr', 'astronomie, conférence'),
(145587, 'Cartographie ren@rde', 'A travers trois expositions et un festival, « Cartographie ren@rde » cherche à comprendre l’évolution récente des processus identitaires par le prisme de l’art contemporain.', '## Dates et horaires à confirmer, merci de vérifier sur le site officiel du lieu de l''événement !\n\nProjet collectif, _Cartographie ren@rde_ est inspiré des réflexions théoriques menées par Paul (Beatriz) Preciado : une interrogation sur l’évolution récente des processus identitaires contemporains, opposant au sein des pratiques culturelles et artistiques deux formes de stratégies politiques. La première, dite « du lion », vise à normaliser les identités, dans un grand récit linéaire lié à la modernité. La seconde, dite « du renard », réaffirme les singularités irréductibles des identités, issues d’un croisement complexe entre territoires, cultures et trajectoires individuelles. Une « cartographie renarde » se constitue, de milliers de récits qui se croisent, s’opposent, se répondent, jouent et attestent aussi d’un grand basculement : l’irruption des nouvelles technologies, les sciences du vivant et la réduction inéluctable de la biodiversité.\n\nLe projet _Cartographie ren@rde_ cherche à voir, comprendre et analyser ce champ appliqué à l’art contemporain. Il propose trois expositions, un festival et quatre modes d’interrogations : chaque lieu s’intéressant plus particulièrement à un ensemble d’œuvres ou à un thème.\n\nLe _Centre d’art Transpalette_ se propose de construire une exposition plus historique (de 1977 à nos jours). Il présente une sélection d’œuvres historiques et récentes — dessins, photographies, installations, vidéos, performances et traces de performances — issues à la fois des collections du Centre Pompidou et de collections privées : Gina Pane, Pipilotti Rist, Anne-Marie Schneider, William Burroughs, John Giorno, Derek Jarman, Michel Journiac, Paul McCarthy, Bruce Nauman, Natacha Nisic et plus de dix autres artistes.\n\nLes _Rencontres Bandits-Mages_ répondent par une mise en jeu de la « cartographie ren@rde » à travers la fabrication collective d’un espace d’exposition, de performance et de projection d’objets vidéos et cinématographiques issus des collections du Centre Pompidou et d’autres institutions françaises et internationales.\n\nQuant à _La Box de l’Ensa_, elle choisit de présenter une œuvre emblématique des collections du Centre Pompidou liée à cette thématique.\n\nÀ travers un programme de performances et d’interventions, le _49 Nord 6 Est – Frac Lorraine_ tente de voir comment le champ du post-porn enrichit ce débat.', 'fr', NULL),
(145588, 'Bal Afro-Latino - Felabration w/ Kologbo & Monkuti', 'Afrobeat, Cumbia', '❉ ▬ LE BAL AFRO-LATINO DE PANAME #5 special FELABRATION ▬ ❉▬▬▬▬▬▬▬▬▬▬▬ Hommage à Fela Kuti ▬▬▬▬▬▬▬▬▬▬▬\n\n◈ OGHENE KOLOGBO from EGYPT 70''s (afrobeat/live) ◈◈ MONKUTI (afrobeat/live) ◈ ◈ DJ CUCURUCHO & MOODY MATT (tropical grooves) ◈\n\n▧ ▧ ▧ 29 OCT 2016 ▧ ▧ ▧ 20H A 5H ▧ ▧ ▧ 8€ / 5€ (after party) ▧ ▧ ▧\n\n★|★▬▬▬▬▬▬▬▬▬▬▬ STYLES ▬▬▬▬▬▬▬▬▬▬▬★|★\n\n✦ AFROBEAT ✦ CUMBIA ✦ CHAMPETA ✦ AFRO FUNK ✦ SOUKOUSS ✦ BULLERENGUE ✦ AFRO PERUANO ✦ COUPE DECALE ✦ RAGGA ✦ DANCEHALL ✦ MANDINGO BEAT ✦ ANTILLES ✦ CALYPSO ✦ ZOUK\n\n●|● ▬▬▬▬▬▬▬▬▬▬▬ L I N E - U P ▬▬▬▬▬▬▬▬▬▬▬ ●|●\n\n★ LIVE ★\n\n● OGHENE KOLOGBO (Nigeria - Afrobeat / Live ) ● Le légendaire guitariste Oghene Kologbo est né a Warri, au Nigeria en 1957\\. Son père était un musicien highlife bien connu: Joe King Kologbo. A 13 ans il rejoint le maitre de l’Afrobeat Fela Kuti. Kologbo a enregistré plus de trente albums avec Fela. Principalement guitar ténor il a aussi enregistre basse et guit rythmique au sein des legendaires Africa 70\\. Kologbo était l’assistant de Fela ‘le magnétophone humain’ son travail était de se rappeler les mélodies que Fela lui chantait tard dans la nuit, et de les enseigner le lendemain au cours des répétitions au groupe Africa 70\\. En 1978, après un concert au Festival de Jazz de Berlin, Kologbo a quitté le groupe avec Tony Allen et quelques autres, ils sont restés à Berlin. Dans les années 1980 et les années 1990, Kologbo travailla avec le légendaire Roots Anabo. Il a aussi enregistré avec King Sunny Ade (Synchro System) et Brenda Fassie, parmi d’autres.https://www.facebook.com/OgheneKologbohttps://www.youtube.com/watch?v=QWJbl0yyGk4\n\n● MONKUTI (Afrobeat / Live ) ● Monkuti convoque les rythmes Vaudoun du Bénin associés au groove céleste de l''afrobeat Nigérian.https://www.facebook.com/monkutimusichttps://www.youtube.com/watch?v=l16Dwb5VPUk\n\n★ DJ SET ★\n\n● CUCURUCHO (Groovalizacion Radio / Tropical Grooves) ●Co-fondateur de Radio Groovalizacion et basé Paris, nomade sonore spécialiste de la sono-tropical et les fusions improbables entre la musique afro, caribe, latin, arabe ou indien avec des rythmes urbaines globaux... Ce véritable groove-trotter a partagé des soirées avec artistes internationales comme Bomba Estereo, Seu Jorge, Balkan Beat Box, Salif Keita, Systema Solar, Dhoad Gypsies of Rajasthan, La Yegros ou Chicha Libre. Showcase au Womex 2013.https://www.facebook.com/djcucuruchohttp://www.mixcloud.com/musicasmigratoriashttp://www.groovalizacion.com/cucurucho\n\n● MOODY MATT (Inna di Mood / Afro Grooves) ●Du reggae à foison, des musiques tropicales, du Hip-Hop épique, des instrumentaux revisités, des variantes remixées et des versions dubifiées, INNA DI MOOD Podcast regorge de musiques savoureuses patiemment sélectionnées et assemblées en mixes thématiques.www.innadimood.com', 'fr', 'Montreuil, Afro beat, Felabration, Fela Kuti'),
(145589, 'Tiers Lieux Hors les Murs (lilO à Livron-sur-Drôme)', 'L''espace lilO à la rencontre des habitants', 'Aujourd’hui les tiers-lieux en Drôme sont nombreux et proposent des activités nombreuses et variées, et notamment du coworking. Pour mieux les comprendre, l’opération Tiers-lieux Hors Les Murs délocalise ces espaces et les amène au cœur des villes, à la rencontre des habitants.\n\nCette deuxième édition aura pour thématique « la recette d’un tiers-lieu ».\n\nLes animateurs « chefs » tenteront de mélanger les bons ingrédients et proposer des activités appétissantes au public pour leur mettre l’eau à la bouche en matière d’outils numériques, par exemple.\n\nRDV au marché de Livron-sur-Drôme dès 9h00 le mardi 27 septembre 2016 avec lilO.', 'fr', ', tiers-lieux');
