(146246, 'Fest-Noz #SETU', 'Fest-Noz de rentrée de l''association Setu!', 'Fest-Noz de rentrée de l''association Setu!\n\nAvec:\n\nPLANTEC\n\nLes Frères Guichen\n\nSparfell\n\nLe Pennec - Lamezec - Le Guen\n\n7€\n\nSalle sous la mairie - Brest', 'fr', ',       Fest-Noz,      Bretagne,     Breizh,    Danse,   Musique,  Traditionnel, Etudiants'),
(146247, 'La police scientifique', 'Exposition de Centre-Sciences', 'Suivez une enquête policière et découvrez différents aspects des analyses scientifiques qui peuvent être menées par les personnels des services d''identité judiciaire.', 'fr', NULL),
(146248, 'Sherlock Holmes, Détective Conseil', 'Soirée Jeux', 'De maigres indices pour des enquêtes épineuses qui n’attendent que vous pour être résolues... Devenez détectives le temps d’une soirée !', 'fr', NULL),
(146249, 'Réunion des sympathisants, amapiens et producteurs de l''AMAP de l''Yvette', 'Réunion pour présenter l''association, ses producteurs partenaires et lancer la souscription des contrats.', NULL, 'fr', ', AMAP Yvette'),
(146250, 'Menez l’enquête avec la Maison des Jeux de Touraine', 'Ateliers Jeux', 'Découvrez des jeux de société sur le thème de la police. En résolvant des énigmes, mettez à l’épreuve votre esprit de déduction.\n\nà partir de 6 ans\n\nVotre mission si vous l’acceptez : Désamorcez une bombe en moins de 5 minutes. Pour y arriver, il faudra être une équipe soudée et à l’écoute !\n\nà partir de 12 ans\n\nLes plus jeunes auront aussi leur enquête à résoudre: un vol de doudou a eu lieu à la bibliothèque, à vous de retrouver le coupable !\n\nà partir de 4 ans', 'fr', NULL),
