(146254, '1er café citoyen de La Rochelle', 'Venez nombreux, qui que vous soyez, partager avec nous vos questions, vos attentes, vos envies, vos actions, dans un esprit de bienveillance.', NULL, 'fr', NULL),
(146255, 'Ville contributive : Co-créer la ville de demain !', 'Les nouveaux modes de collaborations permis par les technologies / table ronde suivie d’un BARCAMP', 'À l’heure de la ville collaborative, de nouveaux modèles de développement émergent, ayant un impact sur l’économie. L’attractivité d’une ville et sa capacité à créer de la valeur est aujourd’hui fortement corrélé sur la capacité de tous ses acteurs à mener des projets contributifs.\n\n« Les ressources cognitives d’une ville»,  ou plus précisément ses « ressources contributives » deviennent un enjeu stratégique de développement. Le déploiement de la fibre, s’il n’est pas corrélé à la mise en place de « nouveaux usages », perd intrinsèquement de sa valeur. Par ailleurs, il est fondamental que les nouveaux modes de collaborations permis par les technologies ne soient pas cannibalisés par des grandes entreprises. Penser sa ville, c’est aussi réfléchir à des choix technologiques préservant les biens publics, les associations, les commerçants, les habitants. Plus que jamais, les choix de logiciels libre ou propriétaire et le choix des licences pour les DATA seront à terme déterminants pour l’avenir d’une ville.\n\nDans ce sens, le caractère collaboratif des initiatives doit renforcer la contribution « des initiatives » publique et/ou privées. Les différentes initiatives collaboratives initiées au sein des villes peuvent-elles à terme être mutualisées au sein d’une R&D commune ?\n\nÀ la croisée des mouvements de l’Open Source et de l’Open Innovation, il pourrait être pertinent de définir un cadre d’intérêts communs des villes visant à mutualiser des ressources et des projets de développement.\n\nChaque ville pourra ainsi apporter « sa brique » en matière d’innovation, qu’elle soit liée à des avancées techniques ou d’usages. Un réservoir collectif « des pratiques contributives » pourrait à terme démultiplier les projets de développement.\n\nCo-créer les villes de demain ne peut se faire qu’en favorisant le dynamisme de l''intelligence collective et la circulation des connaissances.\n\nMais c’est aussi anticiper de nouveaux modes de consultations publiques, et réfléchir à une « démocratie plus ouverte » impliquant d’avantage les habitants dans les choix de gestion de leur ville.\n\nL’agglomération de Nevers, la ligue de l’enseignement 58 et Paris Open SourceSummit, Nevers Libre,  vous invitent le 10 octobre à 18h00  à la Galerie Usaniii 27 Bis rue Saint Etienne 58000 à la table ronde :  « Ville Contributive : Co-créer la ville de demain ! »\n\nAvec\n\n-          Alain Bourcier, Vice-Président en charge du numérique de l’Agglomération de Nevers\n\n-          Caroline Corbal, Présidente de Démocacy OS France\n\n-      Julien Lecaille, Assemblée des Communs de Lille / Communecter\n\n-          Clémens Damien, Développeur Communecter\n\n-          Christophe Boutet, Président de Silicon Comté\n\n-          Claudie Héline, Responsable de la Coopérative des savoirs, université populaire et buissonière\n\n-          Fabien Bazin , Vice-Président du Conseil départemental de la Nièvre\n\nCette table ronde sera animée par Olivier Blondeau, Expert smart-cityzen, chroniqueur à Makery et co-fondateur du projet CitizenWatt.\n\nCette table ronde sera suivi d’un BARCAMP à la Galerie USANII 27 bis rue Saint Etienne organisée par l’association Nevers Libre.', 'fr', NULL),
(146256, 'RDV Jardin Eclairicie', 'Jardin + cabane', NULL, 'fr', NULL),
(146257, 'Open House ', 'Contemporary house with architecture office', 'The Cherry Tree House is a project that re-thinks basic architecture and the dynamic of our life in this new century :  open, efficient, connected, multi-task, in flux, integrated into the existing environment.\n\nThe question that interests me is :  how can architecture fulfill its primary role of protecting us from the elements and at the same time ameliorate its harmony with the environment, nature, our dreams, our artistic ideas, to produce an architecture which is peaceful, innovative, extraordinary, in the end audacious.', 'en', ',   Contemporary,   glass,  energy efficient'),
(146257, 'Portes ouvertes "Maison contemporaine individuelle avec cabinet d''architecte"', 'portes ouvertes', 'La Maison des Cerisiers est un projet qui repense l’architecture quotidienne et la dynamique de notre vie de ce nouveau siècle : ouverte, efficace, connectée, multi-tâche, en flux, intégrée dans l’environnement comme tel.\n\nLa question qui m’intéresse est : comment l’architecture peut-elle remplir son rôle premier de nous protéger des éléments et en même temps améliorer son harmonie avec son environnement, la nature, nos rêves, nos idées artistiques, rendant cette architecture paisible, innovatrice, extraordinaire, enfin audacieuse?', 'fr', ',   Contemporaine,   verre,  efficacité énergétique '),
(146258, 'Week End Innovation Tourisme', 'Concours de la meilleure application mobile créée en 48h', 'Développement d''un concept d’application touristique à présenter devant un jury de professionnels.', 'fr', ', #Tourisme #Digital');
INSERT INTO `${schema}` (`id`, `title`, `description`, `free_text`, `lang`, `tags`) VALUES
(146260, 'SwitchUp Challenge', 'Comment utiliser l’Internet of Everything pour résoudre les défis sociétaux et environnementaux du 21e siècle ?', 'Epitech partenaire du switchUp Challenge!\n\nLe SwitchUp Challenge est un programme qui soutient l’innovation technologique au service d’une société plus juste, plus durable, plus accessible et plus connecté Le programme a pour objectif d’accompagner et récompenser les étudiants et entrepreneurs qui utilisent les nouvelles technologies pour répondre aux défis sociétaux et environnementaux', 'fr', ',  #Challenge #Prototype, #startup'),
(146261, 'Conférence : "Père, mère, fonction incertaine"', 'Pour chaque enfant,  c''est la famille conjugale qui est le premier lieu de l''humanisation. Les fonctions de la mère et du père restent différenciées et asymétriques.', 'Même si aujourd''hui, le mot de parentalité laisse souvent entendre le cas contraire, dans la plupart des cas, la mère est le premier autre, le père intervient en deuxième.Cependant, du fait des évolutions sociales de plus en plus de situations peuvent diverger de ce modèle, alors même que l''extension d''un parental qui serait neutre du point de vue de la sexuation tend à croître. L''intervenant rendra compte des raisons de cette évolution et de la complexité des questions qu''elle pose.\n\nAvec Gérard Neyrand, sociologue, professeur  à l''université de Toulouse, membre de l''équipe d''accueil CRESCO, directeur du CIMERSS, laboratoire associatif à Bouc Bel-Air. Il fait partie du comité de rédaction des revues Dialogues et Recherches familiales et participe au conseil scientifique de l''Espace Andrée Chedid. Il a publié de nombreux ouvrages : _Le dialogue familial, un idéal précaire_ (Erès 2009), _Monoparentalité précaire et femme sujet_, avec Patricia Rossi (Erès 2004), _Soutenir et contrôler les parents_ (Erès-poche 2011)\n\n**Cette conférence est organisée dans le cadre du cycle "Parentalité et fonctions parentales"** Parentalité, famille, fonction paternelle, fonction maternelle... Chacun peut naturellement se perdre dans ces différentes expressions. Au travers de trois regards différents, le psychanalyse, le sociologue et l''anthropologue nous éclaireront sur ces différentes conceptualisations.\n\n**Les soirées-conférences de l''espace Parent Enfant** Sous le thème générique "pour mieux comprendre la condition parentale", ces soirées-conférences son animées par des intervenants reconnus pour la qualité de leur travaux et leur expertise. Véritables temps d''apports d''expériences, de pratiques professionnelles, de réflexions, elles sont suivies d''un débat avec le public.', 'fr', 'conférence,     parent,    parentalité,   enfant,  père,  mère'),
(146262, 'Zola et la Musique', 'Conférence sur les mutations de la musique au tournant du XXème siècle, au regard de l''oeuvre et de la vie d''Emile Zola', NULL, 'fr', 'Emile Zola,  musique'),
(146263, 'Stand de la représentation de l''IRD à La Réunion, à Mayotte et aux Iles Eparses', 'Présentation ludique des activités de l’IRD à La Réunion et dans la zone océan Indien', 'Le stand a pour objectif  :\n\n1/ de présenter les activités de l’IRD à La Réunion et dans la zone OI (Madagascar, Maurice, Mayotte, Comores, Afrique du Sud, Mozambique, Seychelles, …) :\n\n*   santé : TIS-Moustiques ; maladies infectieuses ; accès aux soins ;\n*   environnement-ressources : biodiversité marine et halieutique ; observation spatiale ; biodiversité-génétiques des plantes-organismes sol et plantes\n\n2/ de jouer au jeu MARECO : La mallette pédagogique MARECO « Le récif corallien entre nos mains » a été conçue et réalisée par l''IRD autour d’un même objectif : sensibiliser et responsabiliser les générations futures à la protection des écosystèmes coralliens\n\n3/ de présenter d''autres activités de recherche de manière ludique :\n\n-  Jeu de 7 familles : Le jeu « la vie cachée des sols » vous emmène dans un monde peu visible et pourtant si proche de vous. Découvrez en vous amusant les organismes des sols, leur environnement ainsi que les scientifiques et les outils ayant permis leur étude\n\n- Projections de film sur les recherches passés et en cours sur les 5 continents.', 'fr', ',   Recherche,   Développement, Biodiversité'),
(146264, 'Visite commentée de l''exposition "L''Oeuvre architecturale de Le Corbusier. Une contribution exceptionnelle au Mouvement Moderne"', 'Suivez une visite commentée de l’exposition qui présente dans la maison La Roche les 17 œuvres – bâtiments ou sites réalisés entre 1923 et 1955 – qui figurent dans la série inscrite à l’UNESCO.', 'Le Comité du patrimoine mondial de l’UNESCO a inscrit, au mois de juillet 2016, L’Œuvre architecturale de Le Corbusier sur la Liste du patrimoine de l’Humanité. La valeur universelle exceptionnelle de la série transcontinentale proposée par sept pays (Allemagne, Argentine, Belgique, France, Inde, Japon, Suisse) a été reconnue unanimement par l’UNESCO.\n\nÀ cette occasion, la Fondation Le Corbusier présente dans la maison La Roche les 17 œuvres - bâtiments ou sites réalisés entre 1923 et 1955 - qui figurent dans la série inscrite à l’UNESCO. Chacun des bâtiments est illustré à l’aide de photographies, de plans et/ou de maquettes.', 'fr', ',      Le Corbusier,     architecture ,    oeuvre ,   mouvement moderne,  patrimoine mondial, UNESCO'),
(146265, 'Conférence : "Métamorphose de la parentalité"', 'Moins de mariages, augmentation des divorces, recomposition des familles, maintien du lien de filiation, mariage pour tous, vers quoi nous mènent les bouleversements en cours au sein de la famille ?', 'Qu''annoncent les mutations en cours ? Autant de sujets qui seront partagés avec les participants de cette conférence.\n\nAvec Maurice Godelier, ancien directeur scientifique du département des sciences de l''homme et de la société au CNRS, dont il est médaillé d''or. Maurice Godelier est directeur d''études à l''EHESS. Ses derniers livres sont autant de classiques : La Production des grands hommes (Fayard, 1982) _L’Énigme du don_ (Fayard, 1996) _Métamorphoses de la parenté_ (Fayard, 2004) _Au Fondement des Sociétés Humaines._ _Ce que nous apprend l''anthropologie_ (Albin Michel, 2007), _L''Imaginé, l''Imaginaire et le Symbolique_ (CNRS, éditions 2015).\n\n**Cette conférence est organisée dans le cadre du cycle "Parentalité et fonctions parentales"** Parentalité, famille, fonction paternelle, fonction maternelle... Chacun peut naturellement se perdre dans ces différentes expressions. Au travers de trois regards différents, le psychanalyse, le sociologue et l''anthropologue nous éclaireront sur ces différentes conceptualisations.\n\n**Les soirées-conférences de l''espace Parent Enfant** Sous le thème générique "pour mieux comprendre la condition parentale", ces soirées-conférences son animées par des intervenants reconnus pour la qualité de leur travaux et leur expertise. Véritables temps d''apports d''expériences, de pratiques professionnelles, de réflexions, elles sont suivies d''un débat avec le public.', 'fr', 'conférence,     parent,    parentalité,   enfant,  père,  mère'),
(146266, 'Café outil - Gérez vos tâches et optimisez votre temps avec Wunderlist', 'Gestionnaire de tâche collaboratif', 'L''équipe du Pôle Numérique teste régulièrement des nouveaux outils (logiciels, applications, services, équipements ...) que nous vous proposons de les découvrir sous la forme d''un retour d''expériences.\n\nLe format : 30 minutes de présentation + 30 minutes d''échanges, de pratique et de test.Les outils que nous vous présentons, nous les avons testés dans un contexte d''utilisation professionnel et dans différents environnements (au bureau, en salle de réunion, en mobilité, dans un espace de coworking...)Ces solutions visent à faciliter la collaboration en interne et en externe, à optimiser certaines tâches, à améliorer la productivité, à nous faciliter la vie tout en évitant la surcharge d''information et la distraction numérique.\n\nLes outils et solutions retenues sont techniquement faciles à mettre en œuvre sans investissement lourd pour des petites structures, TPE, travailleurs indépendants, salariés, élus. Disponibles sur le web en mode hébergé, elles peuvent aussi être déployées dans des organisations plus grandes.\n\nAu programme de ce café outil :\n\nla gestion des tâches personnelles ou en équipe pour mener à bien vos projets, planifier un évènement afin de mieux organiser votre temps.\n\n[http://www.howtochoosealaptop.com/wp-content/uploads/2015/03/Wunderlist-logo.jpg](http://www.howtochoosealaptop.com/wp-content/uploads/2015/03/Wunderlist-logo.jpg)\n\n[https://docs.google.com/forms/d/e/1FAIpQLScXsppBW7OvHYGkCAYbd_Hzs6ft4UUY3Mm7VwMlCtQNZ5LPTQ/viewform](https://docs.google.com/forms/d/e/1FAIpQLScXsppBW7OvHYGkCAYbd_Hzs6ft4UUY3Mm7VwMlCtQNZ5LPTQ/viewform)\n\nCette action est cofinancée par l''Union européenne, la Région Auvergne-Rhône-Alpes et le Département de la Drôme.', 'fr', 'veille, collaborative, participative, numérique, digital, startup, curation'),
(146267, 'Goûter 3D !', 'Atelier découverte de l''impression 3D pour les enfants', 'Comment fonctionne cette machine extraordinaire dont on parle tant ?\n\nLes enfants découvriront le fonctionnement de l''imprimante et pourront repartir avec un petit objet imprimé !\n\nInscription par mail : [martinetteuse@laforgecollective.fr](mailto:martinetteuse@laforgecollective.fr)\n\nUn goûter sera offert par La Forge Collective.', 'fr', NULL),
(146268, 'Emile Zola et son atelier photographique', 'Présentation des travaux photographiques d''Emile Zola à travers les prismes de l''innovation et de l''histoire.', 'En photographie comme en écriture, Zola est un expérimentateur et un innovateur.  Il essaie différentes techniques, différents cadrages notant sur son carnet d''atelier non seulement les temps de pose, la qualité de l’éclairage (qui le préoccupe), le matériel utilisé mais aussi ses réflexions esthétiques. Son entourage familial et amical pose de bonne grâce pour le « maître de Médan » et s’initie volontiers à l’art photographique. Alexandrine et son petit cousin Albert Laborde sont les plus assidus. C’est ainsi que naît à Médan ce que l’on pourrait appeler, à l''instar de l''atelier Nadar, l’atelier photo d’Émile Zola.', 'fr', 'Zola, photographie, innovation, Médan'),
(146269, 'Salon de l''Orientation', 'Salon des Métiers du Numérique', NULL, 'fr', ', #l''Etudiant #Numérique #Digital'),
(146270, 'Le circaète', 'musique live I vidéo I bande-dessinée I théâtre', 'Le circaète est un rapace. Le narrateur le découvre planant dans le ciel, alors qu’il est en Lorraine, au début des années 1990, appelé parmi les appelés du service militaire. Instant de poésie volé à une année unique.  \n\nManu Larcenet s’est inspiré de son expérience personnelle pour en faire une bande-dessinée, marquant le début d’une carrière graphique époustouflante et souvent récompensée (Blast, Le combat ordinaire, Le retour à la terre, et tant d’autres).  \n\nS’appuyant sur la bande-dessinée, le spectacle offre une plongée dans cette institution aujourd’hui disparue mais toujours dans les esprits, dans laquelle l’individu disparaît au profit de la masse. Il y est question d’inertie collective, de résignation, mais aussi de la famille avec un humour glacial.  \n\nMêlant théâtre, musique live, arts graphiques et vidéo, cette création rock nous embarque dans le monde ou l’on fabrique des hommes qui marchent au pas.. Ou pas.  \n\nC’est dur, drôle, cynique, poétique, absurde. En somme, c’est humain.', 'fr', 'larcenet,   théo girard,   sébastien brun,   bd,   anne astolfe,   charles vairet,   atlast,   atlastlabel.com,   théâtre,   pulp,   la ferme du buisson,   grange dîmière,   berthelot,   cécile dumoutier,  charles boinot, circaète'),
(146271, 'Petit déjeuner Startup - La Douane au service des startups', 'La Douane partenaire de la French Tech - venez découvrir les services à destination des startups ayant une activité internationale', 'Une heure de présentation et d’échanges pour aider les startups à franchir les frontières en toute sérénité, avec une démarche préventive. Un dossier sera remis à chaque participant.', 'fr', ',       douane,       startup,      frenchtech,     international,    export,   import,  '),
(146272, 'Conférence-débat sur le thème des « Naissances de la pleine lune »', 'Les naissances de la pleine Lune - Quelles sont les réponses de la science ?', 'Les naissances de la pleine Lune : La Lune exerce sa fascination sur les peuples depuis des temps immémoriaux. Nombreux sont ceux qui pensent que le stress, l''insomnie, la criminalité ou encore les admissions aux urgences hospitalières sont soumis à l''influence de l''astre lunaire. Il en est de même pour la survenue des naissances : les nuits de pleine Lune, les hôpitaux et les cliniques seraient débordés. Quelles sont les réponses de la science ?', 'fr', NULL),
