INSERT INTO `${schema}` (`id`, `title`, `description`, `free_text`, `lang`, `tags`) VALUES
(146587, 'Promenade urbaine "Archicache : Habiter, d''Haussmann à aujourd''hui"', 'Promenade dans le 17e arrondissement de Paris', '_Pendant les journées nationales de l''architecture, participez à la plus grande chasse au trésor qui existe actuellement, le geocaching, et découvrez des architectures et des paysages quotidiens, ignorés ou parfois méconnus._\n\nLe logement est l’une des matières premières de la fabrication de la ville. Ainsi les différentes réglementations qui régissent l’aménagement des villes sont indissociables des modes d’habiter. La liberté de plus en plus importante donnée aux architectes depuis Haussmann a permis de faire naître de nouveaux usages. Cette liberté est à la fois le fruit de l’évolution des réglementations et des avancés techniques en matière de construction.\n\nCette promenade vous propose de parcourir l’histoire du logement d’Haussmann à aujourd’hui. A travers six étapes architecturales vous parcourrez le temps depuis la restructuration de Paris, en passant par les prémices de l’industrialisation de la construction jusqu’à l’architecture contemporaine et les nouveaux enjeux de l’aménagement urbain. Attention, il s''agit d''un parcours multi-caches, composés d''un point de départ et de plusieurs étapes, qui mises ensemble permettent de récolter des indices révélant l''emplacement de la cache finale.\n\n**Pour accéder à chacune des notices de ce parcours :**\n\n*   Connectez-vous ou créez votre profil de géocacheur gratuitement sur le sitewww.geocaching.com ®\n*   Téléchargez gratuitement l''application mobile (AppleStore, Google Play) : c:geo / geocaching\n*   Retrouvez des tutoriels déjà existants, vous expliquant le fonctionnement des applications et les étapes de la recherche des caches : [Tutoriel 1](https://tofgeocaching.wordpress.com/2012/02/24/logiciel-geocaching-android-cgeo/) /[Tutoriel 2](http://www.nature-obsession.fr/technologie/trouver-premiere-geocache-grace-application-cgeo.html)', 'fr', ',      promenade urbaine,      habitat,    Haussman,   logement,  aménagement urbain, famille'),
(146588, 'Guerre aux frontières, une bataille coloniale', 'Exposé mis en scène suivi d''un débat proposé par la maison de quartier de Villejean.', '', 'fr', NULL),
(146589, 'Commission Démocratie Nuit debout', 'Débat hebdomadaire', '', 'fr', NULL),
(146590, 'Géographes, à la recherche d’un monde durable', 'Visite guidée de la toute nouvelle exposition', 'Faite de jeux de rôles et de plateaux, maquettes interactives, balade paysagère, puzzle de ville et cartes en tous genres, cette exposition vous permet s de comprendre en vous amusant quels sont les nouveaux enjeux de la géographie moderne. Marketing territorial, géopolitique locale et jeux d’acteurs, développement durable des villes et réflexion sur les modes de déplacements : toutes ces questions d’actualités seront vues à travers 13 jeux et manipulations.', 'fr', ',    géographie,   fabrika sciences,  ville, urbanisme'),
(146591, 'Week-end des Luttes et des Alternatives', 'Manifestation à Notre-Dame-des-Landes', '"Que résonnent le chants de nos bâtons ! Départ de la marche samedi à 10h, dans le Bocage\n\n[https://www.acipa-ndl.fr/actualites/divers/item/686-8-octobre-2016-nddl-que-resonnent-les-chants-de-nos-batons](https://www.acipa-ndl.fr/actualites/divers/item/686-8-octobre-2016-nddl-que-resonnent-les-chants-de-nos-batons)', 'fr', NULL),
(146593, 'Salon Ille-et-Bio', 'Grand rendez-vous des alternatives dans l''ouest', ' [http://www.illeetbio.org/salon-ille-et-bio/](http://www.illeetbio.org/salon-ille-et-bio/)\n\nDimanche, ND Rennes y présentera présentation son action "Réinventons la démocratie" et y poursuivra son travail de recueil de propositions de réformes démocratiques\n\n[https://gazettedebout.fr/2016/09/30/a-rennes-reinventer-la-democratie/](https://gazettedebout.fr/2016/09/30/a-rennes-reinventer-la-democratie/)', 'fr', NULL),
(146594, 'Visites de l''observatoire', 'Venez visiter les batiments historiques de l''observatoire des sciences de l''univers de Besançon', 'Visitez les anciens bâtiments de l''Observatoire et sa magnifique lunette méridienne et observez le soleil avec les membres de l''association astronomique de Franche-Comté pour comprendre d''où viennent les taches, protubérances et autres éruptions solaires', 'fr', ',  observatoire, astronomie'),
(146595, '4 heures pour la Grèce, austérité et santé', 'Par Bretagne Grèce Solidarité Santé', 'À la maison de quartier de Villejean.\n\n[+ d''infos](https://local.attac.org/35/attac-35/agenda/article/aide-aux-grecs-une-caravane-de-brest-a-thessalonique-et-athenes)', 'fr', NULL),
(146596, 'Exposition "Patrimoine architectural du XXe siècle en Haute Corse"', 'Exposition CAUE Haute-Corse', 'L''architecture du XXe siècle est le reflet des transformations de la société. Souvent méconnue, parfois décriée et actuellement menacée, elle témoigne d''une époque marquée par des avancées incontestables. L''évolution des matériaux et des techniques de construction vont permettre aux homme de l''art de créer des formes et des structures innovantes, rompant totalement avec l''héritage classique du siècle précédent.\n\nAinsi le label "Patrimoine XXe" a été crée par le ministère de la Culture et de la Communication en 1999 dans le cadre d''un ensemble d''actions menées en faveur du patrimoine architectural et urbain du siècle.\n\nCette exposition a pour but de mettre en lumière la richesse et la diversité de l''architecture du XXe en Haute Corse.', 'fr', ', Exposition Patrimoine XXe'),
(146597, 'Stand "Atelier à Vélo"', 'Approche de notions scientifiques comme l''effet gyroscopique, comment réparer un vélo et essai de vélos originaux : tamdems,...', NULL, 'fr', NULL),
