INSERT INTO `${schema}` (`id`, `title`, `description`, `free_text`, `lang`, `tags`) VALUES
(146679, 'Concert de Clôture du Festival des Heures; concert des Complies', '5° concert de la journée avec Vivaldi et son contemporain Hasse, interprétés par la violonvelliste Ophélie Gailard et son ensemble Pulcinella, et la Maîtrise de Radio France dirigée par Sofi Jeannin', 'Hasse avec son adagio pour cordes et son Miserere, Vivaldi avec son concerto pour violoncelle et son Magnificat; une violoncelliste acclamée sur toutes les scènes, une maîtrise qui nous fera redécouvrir le Magnificat de Vivaldi à voix égales, tel que voulu par le compositeur.', 'fr', 'Ophélie Gaillard, Sofi Jeannin, Radio France, Vivaldi, Pulcinella, Magnificat'),
(146680, 'Projection du film "Villa Cavrois, le temps d''un songe"', 'La Villa Cavrois analysée au travers de vidéos d’étudiants de Master 1 Faculté d''architecture site St-Luc Tournai ', 'A l’occasion de « L’art dans la ville 2016 », festival qui soutient la jeune création dans le Tournaisis, les étudiants de Master 1 de LOCI Tournai présenteront des travaux de vidéos réalisés dans le cadre du cours de moyen d’expression, encadré par Pascal Marchant, Anne-Sophie Nottebaert et l’artiste Yeung Fun Yuen.\n\nPour l’analyse architecturale de la villa Cavrois, imaginée par l’architecte moderniste Robert Mallet Stevens et construite à Croix près de Lille, les étudiants utilisent pour seul outil, la vidéo : plus de dessins, plus de plans ni de coupes ou autres outils conventionnels d’analyse. L’image animée et le montage des prises vidéo in situ doivent raconter la villa, ses caractéristiques – forme et contenu. Une vingtaine de vidéos ont été réalisées.\n\nSaga:\n\nLa villa Cavrois est construite à Croix pour une famille d''industriel Roubaisien entre 1929 et 1932\\. Elle est sans doute la réalisation la plus emblématique de l''architecte Robert Mallet Stevens.\n\nCette villa a eu "une vie" plutôt tumultueuse...\n\nDurant la seconde guerre mondiale, elle est occupée par l''armée allemande et transformée en caserne, puis après la libération, transformée de nouveau et divisée en deux appartements.\n\nAprès le décès de Mme Cavrois en 1985, elle est rachetée par un promoteur qui souhaite faire une opération immobilière qui ne verra fort heureusement jamais le jour. Puis abandonnée, elle est la proie du vandalisme et de dégradations diverses.\n\nElle est classée monument historique en 1990\\. Enfin, grâce à la mobilisation d''une association de sauvegarde, l''Etat Français acquiert une grande partie de la propriété en 2001\\. Après treize années d''études et de travaux, elle retrouve son état d''origine et à la suite, est rendue à la découverte du public depuis juin 2015.', 'fr', NULL),
(146681, '5° Festival des Heures au Collège des Bernardins', '5 concerts tout au long de la journée, de 9h45 à 22h, ou se côtoieront la musique vocale baroque à lagrande musique sacrée russe, la musique de Chambre, des pages pour choeur et orchestre.  ', '5 concerts tout au long de la journée\n\n- 9h45 Vêpres de Rachmaninov / Ensemble La Tempête dir: S.P. Bestion\n\n- 12h Beethoven, Liszt Debussy par Dominique de Williencourt (violoncelle) et Tanguy de Williencourt (piano)\n\n- 15h The King''s Singers / Byrd, Lassus, Pärt, Swellinck\n\n- 17h30 Marc Antoine Charpentier / La Chapelle Rhénane dir: Benoît Haller\n\n- 20h30 Hasse - Vivaldi /Ophélie Gaillard (violoncelle), Pulcinella orchestra, Maîtrise de Radio France dir: Sofi Jeannin', 'fr', 'King''s Singers, Radio France, Ophélie Gaillard, Williencourt, la tempête'),
(146682, 'Faîtes des Sciences', 'Expériences et manipulations présentées par le collège Emmanuel Saldès', 'Les collégiens présentent des manipulations aux écoliers (CM2) du réseau REP+.\n\nSupports : expériences, jeux\n\nDate non arrêtée par l’établissement scolaire à l’élaboration du programme.', 'fr', ',   REP+,  Sainte-Marie, Sciences'),
(146683, 'C''est le cirque à Nohant !', 'La magie du cirque au travers d''ateliers jonglage, trapèze, magie, acrobaties, jeux d’équilibre...', 'Petits et grands, laissez-vous porter par la magie du cirque lors d’un magnifique spectacle mené par les élèves de l’école de Bourges « Le Nez dans les étoiles ». Découvrez l’univers actuel du cirque et participez aux ateliers jonglage, trapèze, magie, acrobaties, jeux d’équilibre...\n\nAteliers pour les enfants à partir de 7 ans.\n\nRenseignements et réservations 02 54 31 06 04\n\nLieu de rendez-vous : accueil librairie du domaine', 'fr', 'spectacle,       magie,       cirque,       enfants,      ateliers,      jonglage,     trapèze,   acrobaties,   jeux,  '),
(146684, 'La Collectivité Territoriale de Martinique au coeur de l’information préventive sur les risques majeurs', 'Sensibilisation autour des risques majeurs', 'Village des risques dans les jardins de la Collectivité Territoriale à Plateau Roy.\n\n- Ateliers pratiques ,\n\n- Démonstration de gestes de premiers secours,\n\n- Expérimentation du simulateur de séisme ,\n\n- Ateliers d’informations et de sensibilisation\n\n- Conférence…', 'fr', ',     CTM,     Risque majeur,   Conférence,  Atelier, Martinique'),
(146685, 'La Fabrique à histoires', 'Les 22 et 23 octobre 2016, profitez de "Monument jeu d''enfant" pour en profiter pour participer à des ateliers et découvrir l''application "La Fabrique à histoires" au château de Cadillac !', 'Traversez le temps avec l’application la « Fabrique à histoires » !\n\nDepuis les temps anciens, une machine tisse les contes et légendes qui font notre Histoire : c’est la « Fabrique à histoires ». Mais depuis quelques temps les pièces tissées disparaissent… Catastrophe ! Les histoires des monuments sont totalement chamboulées ! Vous avez un défi à relever : remettre l’histoire en place ! Soyez agiles et profitez de l’application et de ses parcours scénarisés pour une visite active avec toute la famille. Découvrez en avant-première la Fabrique à histoires en explorant les salles du château de Cadillac.\n\nAvec les ateliers, partez à la recherche d’indices et imaginez votre propre machine à tisser des histoires.', 'fr', ',        cadillac,        fabrique,       histoires,      ateliers,     application,    littlebits,   machine,  '),
(146686, 'Baguage d’oiseaux', 'Participer à une séance de baguage', 'Venez participer à une séance de baguage à Plateau Boucher (pose de filets, identification, mesures biométriques, baguage…).\n\nPrévoir vêtement de pluie, jumelles…\n\nNiveau de difficulté : 1 (accessible à tous)', 'fr', NULL),
(146687, 'Découverte du pavillon pédagogique «Energies renouvelables» du RSMA', 'Visite du pavillon pédagogique du RSMA', 'Déroulement de la visite :\n\n- Départ en bus vers le site (le lieu de RDV sera communiqué à l’inscription).\n\n- Accueil du RSMA\n\n- Visite du pavillon pédagogique. Objectif : expliquer au visiteur le fonctionnement d’un chauffe-eau solaire,\n\n- Intervention des apprentis sur leur métier, leurs visions de la filière chauffe-eau solaire (solariste)\n\n- Présentation de la filière solaire en Martinique, les acteurs, la réglementation, les métiers, les dispositifs d’aides.', 'fr', 'RSMA,  Energie solaire,  Energies renouvelables, Martinique'),
(146688, 'Soyez un phénix', 'Renaître à l''essentiel, à son essence', 'Nous vivons toutes et tous des moments de doutes, des peurs, des blessures, des défis... Parfois ces moments nous éloignent de nous-même, nous font perdre notre centre. Que ce soit le passé, le futur, la monotonie du quotidien ou les chocs de l''existence, tout autant de raison de se perdre, de perdre l''impression de sens.\n\nPour certain-es, nous ne connaissons pas vraiment notre essence. Qui sommes-nous ? Que somme-nous ? Et surtout, que choisissons-nous d''être ?\n\n**Voici un atelier qui vous invite**, à cette époque où l''énergie de la Nature décroît, **à une mort initiatique** (mourir au passé, à ses illusions, ses étiquettes) **pour renaître à votre** centre, votre **essence profonde**.\n\nVous êtes convié-e à un moment de partage, de quête intérieure mêlant introspection, énergétique et méditation pour vous fournir des outils afin d''émerger des cendres de toutes vos expériences passées pour les transmuter en réalisations futures.\n\n*   -> Prendre un temps pour lâcher ce qui ne nous correspond plus (bilan et exercices de lâcher-prise)\n*   -> Se reconnecter avec sa source intérieure (pratique de recentrage, de connexion à Soi)\n*   -> Définir ses choix à partir de son centre pour laisser la vie rayonner depuis lui tel un mandala\n\n_Cet atelier est indépendant mais ce veut une préparation du cycle qui débutera après les vacances de Toussaint._\n\nInscription annuelle de 10€ pour l''Espace des possibles (lieu géré par une association - valable pour toutes les activités du lieu) + 15€ la séance.\n\nBâtiment A - Résidence Le Rubis 3 Impasse du Tacot des Batignolles, 63200 Riom (merci de rester discrets dans la cage d''escaliers pour le confort de nos voisins)\n\nRenseignements et inscriptions : Xavier Xael Girard 06.38.87.43.91 [xavierxaelgirard@live.fr](http://mailto:xavierxaelgirard@live.fr) [http://xavierxaelgirard.wix.com/meditation](http://xavierxaelgirard.wix.com/meditation)', 'fr', NULL),
(146689, 'La biodiversité martiniquaise peut-elle nous aider à mettre en place une agriculture utilisant moins de pesticides ?', 'Débat autour d''alternatives naturelles aux pesticides.', 'Le recours aux pesticides pour contrôler les ravageurs, les maladies ou les plantes adventices dans les parcelles agricoles et les jardins entraîne des conséquences néfastes sur l’environnement, la biodiversité et l’Homme. Il devient donc nécessaire de trouver des alternatives à l’utilisation des produits phytosanitaires. L’utilisation d’insectes utiles pour la lutte biologique, de plantes cultivées locales peu sensibles aux nuisibles ou bien de plantes de service (pour le contrôle de maladies ou des mauvaises herbes) sont des exemples concrets que la faune et la flore de Martinique peuvent nous aider à construire une agriculture favorisant l’agroécologie.', 'fr', ',   agroécologie,  biodiversité, Martinique'),
(146690, 'L’éruption de la Montagne Pelée de 1929', 'Débat autour de l''éruption de 1929', 'L’environnement .... C’est aussi la nécessaire prise en compte des risques naturels majeurs par la société. La Martinique est confrontée au risque volcanique. L’éruption de la Montagne Pelée de 1929 est méconnue. Pourtant en 1929-1930, l’on dut notamment assurer l’accueil de milliers de réfugiés, une profonde transformation du réseau routier de la Martinique, la construction des observatoires du morne des Cadets et du Fort Desaix...\n\nLa gestion de la crise volcanique de 1929 est riche d’enseignements.', 'fr', ',   Montagne Pelée,  Martinique, Café des sciences'),
(146691, 'WebSchool : optimiser le référencement de votre site web', 'Tout ce que vous avez toujours voulu savoir sur le référencement et ses évolutions récentes.', NULL, 'fr', 'référencement, micro-format, web, site'),
(146692, 'A la découverte des requins et des raies de Martinique', 'Conférence sur les requins et les raies.', 'Conférence grand public sur les requins et les raies. Présentation générale sur leur rôle dans les écosystèmes marins, présentation des études réalisées en Martinique et sur l’ensemble des Antilles françaises (méthodes, résultats).\n\nIntervenante : Océane Beaufort, Coordinatrice du REGUAR (réseau requins des Antilles françaises)', 'fr', ',    Raie,   Requin,  écosystèmes marins, Martinique'),
(146693, 'Biodiversité méconnue de la RBI des Pitons', 'Présentation des premiers résultats sur la faune entomologique de la RBI des Pitons', 'L’un des défis importants de l’humanité dans son environnement concerne la préservation de la biodiversité, élément majeur du bon fonctionnement des écosystèmes, donc de sa survie. Mais pour protéger, il faut d’abord connaître et force est de constater que dans ce domaine, de nombreuses lacunes persistent.\n\nC’est dans ce contexte que s’intègre « l’étude de la faune entomologique et d’autres invertébrés de la RBI des Pitons », programme de recherche pluridisciplinaire sur le terrain dont les buts, les attentes et les premiers résultats seront présentés et discutés avec le public.\n\nIntervenant : Patrick MARECHAL, Président de l’ICNC et Directeur du programme «Pitons»', 'fr', ',  Biodiversité,  Martinique'),
(146694, 'Jeunes publics et culture scientifique', 'Présentation des outils d’information du département culture scientifique de la Bibliothèque municipale de Schoelcher.', 'Présentation des outils d’information et du programme des ateliers proposés par le département culture scientifique de la Bibliothèque municipale de Schoelcher.\n\nUtilisation de documents écrits, audiovisuels, électroniques rassemblés et produits pour les enfants.\n\nVisite de 20 à 30 min par groupe de 20 personnes max', 'fr', ',   Culture scientifique,  pédagogie, Martinique'),
(146695, 'Dans la mer il n’y a pas que des poissons !', 'Sensibilisation à la biodiversité marine.', 'La mer est un lieu où il y a une grande biodiversité. Nous vous proposons de mieux faire connaissance avec les êtres vivants du récif corallien et de voir les menaces pesant sur cet écosystème.\n\nSupports d’animation : affiches, jeux, observations à la loupe de sable corallien', 'fr', ',   Observation,  biodiversité, Martinique'),
(146696, 'Balade nocturne sous les étoiles', 'Description des constellations', 'Acheminement en bus sur un site d’observation du ciel. Descriptions des constellations. Observation à l’oeil nu et avec des instruments.\n\n*   Cible : adultes uniquement\n*   Niveau de difficulté : 1 (accessible à tous)\n*   RDV à 18h00 devant l’ATRIUM (boulevard du Général de Gaulle à Fort-de-France)\n*   Prévoir vêtement de pluie, chaussures fermées, jumelles', 'fr', ',   Constellation,  CDSA, Martinique'),
(146697, 'Visite du centre de tri', 'Présentation de l’activité de tri des déchets d’emballages.', 'Visite de 2h par groupe de 20 personnes max', 'fr', ',   Tri,  Déchets,  Martinique'),
(146698, 'Randonnée palmée sur le sentier sous-marin des îlets du François', 'Le Carbet des Sciences vous propose de découvrir les richesses et merveilles du monde marin au cours d’une randonnée palmée sur son sentier sous-marin dont le départ est situé au François.', 'La mer c’est l’avenir de la Terre ! Le Carbet des Sciences vous propose de découvrir les richesses et merveilles du monde marin au cours d’une randonnée palmée sur son sentier sous-marin dont le départ est situé sur l’îlet Thierry au François. Vous serez encadrez par un moniteur de plongée diplômé d’Etat pour la ballade dans l’eau et par un animateur scientifique pour les activités sur la plage.\n\nLe matériel (palme, masque et tuba) peut être fourni sur demande.\n\nLes enfants mineurs doivent être accompagnés d’un responsable légal.\n\n**Informations pratiques :**\n\n• Accessible à toute personne sachant nager à partir de 8 ans\n\n• Longueur du parcours : 800 m\n\n• Durée : la matinée\n\n• Prévoir nécessaire de bain (maillot, t-shirt pour la protection solaire type lycra, serviette), appareil photo étanche si vous en avez un, eau et encas, lunettes de soleil, casquette, crème solaire de préférence minérale (la crème solaire classique est nocive pour les organismes marins), palmes, masque et tuba si vous en possédez.\n\n RDV au port de pêche du François\n\nRenseignements et inscriptions : mer.carbet.sciences@gmail.com', 'fr', ',   biodiversité,  randonnée palmée, Martinique'),
(146699, 'Un labo à ciel ouvert !', 'L’AME vous invite à découvrir une l’expérimentation dans le domaine des énergies renouvelables.', 'L’AME vous invite à découvrir, sur le site du Centre Hospitalier du François, ce qu’est l’expérimentation dans le domaine des énergies renouvelables. De la centrale photovoltaïque à la batterie de stockage de haute performance, sans oublier les bancs d’essais photovoltaïques, vous aurez l’occasion de visiter un véritable laboratoire de recherche sur l’énergie solaire.\n\n**Informations pratiques :**\n\n• Cible : Collégiens, lycéens, étudiants, grand public\n\n• Visite de 40 min par groupe de 10 personnes max.\n\n   Scolaires : la classe sera scindée en 2 pour une visite en simultanée.\n\n• RDV sur le parking du Centre Hospitalier du\n\nFrançois (Pointe Courchet)\n\n• Renseignements et inscriptions :\n\ncontact@energie.mq ou au 0596 301 591', 'fr', ',   Energie renouvelable,  photovoltaïque,  Martinique'),
(146700, 'LA LOI "ZERO PHYTO"', 'CONFERENCE', 'CONFERENCE organisée par l''Association des Jardins Familiaux de l''Espérance et animée par Dominique BOUTIN de la Société d''Etude, de Protection et d''Amenagement de la Nature en Touraine (SEPANT)\n\n* Impact des pesticides sur la santé & l''environnement.\n\n* Rappel réglementaire sur le «zéro pesticide ».\n\n* Quelques pratiques écologiques à mettre en place dans les jardins.\n\nSalle 120 (1er étage), Les Halles, Place Gaston Pailhou – 37000 TOURS', 'fr', 'Pesticides, santé, environnement, pratiques écologiques, fèglementation'),
(146701, 'AS HANDBALL Lycée Alfred Nobel , Clichy sous bois', 'Démocratisation du handball au lycée Alfred Nobel grâce à la création d''une Association sportive spécifique à cette activité.', 'En septembre 2015 le lycée Alfred Nobel de Clichy sous bois à ouvert une association sportive Handball pour permettre d''exploiter un potentiel certain au sein du lycée et ainsi compléter les autres AS déjà proposées.\n\nDès la première année le lycée a enregistré l''inscription d''environ 20 élèves avec une mixité parfaite , 10 filles et 10 garçons.\n\nDès la 1ère année notre équipe Juniors filles s''est qualifiés pour les Championnat de France de Handball à St Chamond et a terminé 8ème en perdant contre le finaliste de la compétition Besançon.\n\nDe plus notre arbitre masculin, Walid , a participé à la compétition et a raté de justesse la validation France. Il reste arbitre Académique et espère retenter la validation dans un Championnat de France pour obtenir des points en plus au BAC.\n\nEnfin en septembre 2016 , soit la 2ème année d''existence de L''As Handball , l''affluence s''établit à plus de 35 élèves par séance.\n\nNous souhaitons récompenser et surtout accroître cette dynamique "HANDBALL" au Lycée grâce au Mondial de Handball.\n\nEt surtout proposer aux élèves d’assister et de participer à cet événement car le milieu social et culturel des élèves ne permet pas toujours d''avoir accès à ce type d’événement.', 'fr', 'Handball,   intégration,   mixité,   pédagogie,  Education, Autonomie'),
(146702, 'Journée des commoneurs et commoneuses de Lille', 'Commoneurs et commoneuses de Lille et ses environs, travaillons en coworking une fois par mois !', 'Commoneurs et commoneuses de Lille et ses environs, travaillons en coworking une fois par mois !\n\nOn commencerait comme ça :\n\n- Où ? au Mutualab (19 rue Nicolas Leblanc à Lille)\n\n- Quand ? Tous les 2èmes jeudi du mois (pour alterner avec l''Assemblée des Communs en cours de constitution)\n\n- A quelle heure ? De 9h à 19h, on vient quand on veut\n\n- A quel tarif ? Nous sommes en discussion avec le Mutualab pour une prise en charge de l''utilisation du lieu\n\n- Pour quoi faire ? Travailler ensemble dans le même espace physique pour favoriser les échanges directs. On pourra même travailler sur tout autre chose que les communs, l''important c''est d''être au même endroit pour pouvoir interagir facilement avec les autres autour des sujets d''actualité dans les communs du territoire mais pas seulement.\n\nEt puis nous verrons à l''usage pour faire évoluer les conditions (lieu, date, fréquence,...).\n\nAlors ? On se voit le 13 octobre ? :)', 'fr', ', Lille '),
(146703, 'Conférence "EntrepreneurE" ! ', 'L''association Enactus vous invite à une conférence et un cocktail networking où une dizaine d''entrepreneures vous feront part de leurs expériences ! ', 'Comment on dit déjà... "entrepreneuse" ou " entrepreneur" ? Non "EntrepreneurE" !\n\nC’est pourquoi Enactus UPEC propose la conférence « EntrepreneurE ! » pour permettre de mettre en lumière des initiatives entrepreneuriales principalement portées par des femmes.\n\nCette conférence c’est l’occasion de :- De faire avancer son projet de création ou de développement d’entreprise en échangeant avec les conférencières et réseaux d''accompagnement à la création, notamment au féminin ;- De profiter des conseils et retours d’expériences d’entrepreneures et d''experts ;- De développer son réseau en rencontrant d''autres entrepreneures.\n\nLes femmes créatrices d’entreprises - ou en passe de le devenir - se donnent donc rendez-vous au Campus Créteil de l’Université Paris-Est Créteil le 11 Octobre à 18H.\n\nProgramme :- 18h : Introduction par l’équipe Enactus UPEC- 18h15-19h30 : Intervention de créatrices d’entreprises- 19h30-21h : Cocktail Networking\n\nBien évidemment, tout le monde y est convié, que ce soit les porteurs de projets femmes ou hommes, des entrepreneurs débutants ou avertis, et des étudiants ou professionnels curieux.', 'fr', ',     Entrepreneuriat,     entrepreneure,   région parisienne,  start-up,  '),
(146704, 'Les abeilles et la pollinisation', 'Découvrez les formidables pollinisateurs que sont les abeilles.', 'La pollinisation est un service rendu par la nature aux hommes puisque 70% de la nourriture que l’on consomme dépends directement des pollinisateurs. Les abeilles sont les principaux pollinisateurs des cultures et leur diversité est bien plus importante que l’on croit. Tout le monde connaît l’abeille à miel... mais connaissez vous les 970 autres espèces qui vivent en France et qui sont très utiles à la pollinisation ?', 'fr', ', pollinisation - abeilles - diversité'),
(146705, 'RDV Carole Vannerie', 'P''ti caf'' au Don Camillo', NULL, 'fr', NULL),
(146706, 'Découvrir la phénologie avec l''Observatoire des saisons Provence', 'Apprenez à observer les rythmes saisonniers d''espèces animales et végétales', 'Venez vous initier à la phénologie, qui consiste à observer les rythmes saisonniers d''espèces animales et végétales et exercez votre sens de l''observation.', 'fr', NULL),
(146707, 'Chèvrefeuille, sauras-tu garder tes arbres et ton troupeau?', 'Mettez-vous dans la peau d''un éleveur devant répondre aux besoins de son troupeau.', 'Lors de cette animation, vous serez invité à vous mettre dans la peau d’un éleveur devant répondre aux besoins alimentaires de son troupeau. Vous disposerez alors d’une exploitation d’arbres fourragers, première source alimentaire du troupeau. L’objectif du jeu sera d’assurer son alimentation sur une période de dix années grâce à une exploitation raisonnée des arbres fourragers présents. Saurez-vous garder vos arbres et votre troupeau ? Quelle stratégie adopterez-vous face aux aléas climatiques que vous rencontrerez ?', 'fr', ', chèvrefeuille - jeu - alimentation - arbre - troupeau'),
(146709, 'Le mercure dans l''Arctique', 'Partez à la découverte du mercure et embarquez-vous dans une campagne en Arctique.', 'De nombreux oligo-éléments sont essentiels pour la vie marine et influencent le fonctionnement des écosystèmes océaniques et le cycle global du carbone. Certains oligo-éléments sont également source de préoccupation en tant que contaminants, tandis que d’autres, avec un large éventail d’isotopes, sont utilisés pour évaluer les processus modernes océaniques et le rôle de l’océan dans le changement climatique passé. Cette année le MIO vous parlera d’un de ces oligo-élements présents dans le milieu marin : le Mercure ! Ce sera l’occasion de vous montrer les images magnifiques d’une campagne en Arctique récente effectuée dans ce cadre et le matériel du MIO utilisé pour les campagnes océanographiques !', 'fr', ', Arctique - mercure - écosystème océanique - changement climatique'),
(146710, 'AJN 2 : La culture sur butte : le Graal?', 'Atelier jardinage naturel 2', NULL, 'fr', NULL),
(146711, 'Visite architecturale et projection du film "SEA - Site expérimental d''architectures"', 'Au bout du plongeoir, Domaine de Tizé développe un site expérimental d''architectures, lieu d''expérimentation à échelle 1 pour le monde du bâti, les jeunes en formation, les citoyens curieux.', 'L’association Au bout du plongeoir, implantée depuis 10 ans sur le Domaine de Tizé, met en place en partenariat avec Rennes Métropole, gestionnaire du site, et l’ensemble de ses partenaires publics, le SEA – Site Expérimental d’Architectures.\n\nLe SEA a pour vocation de transformer le Domaine et son Manoir en concordance avec la vie artistique et culturelle qui s’y développe tout en questionnant les grands enjeux de l’architecture et de l’aménagement aujourd’hui.\n\nDes expérimentations se mènent ainsi au Domaine de Tizé que nous vous proposons de découvrir ou redécouvrir :\n\n- transformation du Manoir du 14è siècle avec l’architecte Charles Motte et le charpentier Jean-Yves Riaux,\n\n- collaboration d’un architecte, Mickaël Tanguy, et d’un auteur, Alexandre Koutchevsky, autour d’un mur en terre,\n\n- création de vitraux pour l’étable avec un groupe de jeunes accompagnés par Tout Atout.', 'fr', 'architecture, expérimentation, friche agricole, laboratoire d''art et architecture,  lieu de rencontres'),
(146712, 'SEA - Site expérimental d''architectures', 'Au bout du plongeoir, Domaine de Tizé développe un site expérimental d''architectures, lieu d''expérimentation à échelle 1 pour le monde du bâti, les jeunes en formation, les citoyens curieux.', 'L’association Au bout du plongeoir, implantée depuis 10 ans sur le Domaine de Tizé, met en place en partenariat avec Rennes Métropole, gestionnaire du site, et l’ensemble de ses partenaires publics, le SEA – Site Expérimental d’Architectures.\n\nLe SEA a pour vocation de transformer le Domaine et son Manoir en concordance avec la vie artistique et culturelle qui s’y développe tout en questionnant les grands enjeux de l’architecture et de l’aménagement aujourd’hui.\n\nDes expérimentations se mènent ainsi au Domaine de Tizé que nous vous proposons de découvrir ou redécouvrir :\n\n- transformation du Manoir du 14è siècle avec l’architecte Charles Motte et le charpentier Jean-Yves Riaux,\n\n- collaboration d’un architecte, Mickaël Tanguy, et d’un auteur, Alexandre Koutchevsky, autour d’un mur en terre,\n\n- création de vitraux pour l’étable avec un groupe de jeunes accompagnés par Tout Atout.', 'fr', 'architecture, expérimentation, friche agricole, laboratoire d''art et architecture,  lieu de rencontres'),
(146713, 'Festival des deux infinis 2016', 'Pour un événement astronomique valorisant l’image d’une science vivante, évolutive, mobilisant les scientifiques et les profanes autour d’échanges, de rencontres.', 'Du **25/09 au 19/10** se déroulera la 6e édition du Festival des deux Infinis, désormais célèbre rendez-vous francilien, devenu un incontournable pour tous les passionnés d''astronomie, avec le soutien de la Ville de Paris, de l’In2P3 et du LPNHE en y associant le Conseil Régional.\n\nAu programme de cette nouvelle édition :\n\n*   **samedi 15/10** : _**journée marathon de conférences**_ avec pas moins de 7 conférences gratuites à l''UPMC, retransmises en simultané sur le web\n*   un évènement pour vivre en direct "les embrassades" de la comète Tchouri et de la sonde Rosetta en direct\n*   **samedi 01 et 08 octobre :** deux **soirées d''observation "Montsouris sous les étoiles"** dont une organisée dans le cadre du Jour de la Nuit avec la présence de clubs partenaires ainsi qu''une conférence autour de la Lune\n*   **samedi 08 octobre** : une après-midi d''observation du Soleil\n*   des portes ouvertes dans les clubs franciliens\n*   **Tous les week-ends du 1e au 16 octobre** : _balades et randonnées parisiennes_ autour de son patrimoine astronomique ainsi que des visites de laboratoires\n*   mercredi 19 octobre : une nouvelle édition de notre concours **"Ma thèse en 5 minutes"** retransmis en simultané sur le web\n\nProgramme complet et plus d''informations sur https://www.afastronomie.fr/festival-2-infinis', 'fr', ',      astronomie,      balade,     randonnées,    ,  patrimoine,  observations'),
(146714, 'Lancement du projet LOCUS', 'Projet issu de la synergie moon shot à développer en hub', 'L''objectif de cette session est de clarifier le projet Locus présenté en Moonshot pour étudier les modalités de son établissement en projet HUB.\n\nLe projet LOCUS consiste en la réalisation de visite virtuelle de bâtiments du monde entier en réalité virtuelle', 'fr', ',    MOONSHOT,   REALITEVIRTUELLE,  EPITECH, PROJETHUB'),
(146715, 'Coaching solidaire', 'Mets tes compétences au service des associations', 'Présentation de:\n\n- ZupdeCo, des interlocuteurs directs et de la mission des étudiants d''Epitech auprès des jeunes en difficulté scolaire.\n\n- Emmaus Connect, des interlocuteurs directs et de la mission des étudiants d''Epitech auprès de l''accompagnement pédagogique pour les personnes ayant des difficultés d’accès au numérique.', 'fr', ',    associations,   zupdeco,  emmausconnect, coachingsolidaire'),
(146716, 'Venez fêter la science avec l’Esprit Sorcier !', 'L’Esprit Sorcier et 15 grands instituts de recherche français vous invitent à la Cité des sciences pour un grand week-end de science festif et pédagogique. Ca va être bien !', 'Oyez oyez ! Pour ouvrir en grande pompe la Fête de la Science 2016, l’Esprit Sorcier s’associe au Ministère de l’Education nationale et à 15 grands instituts de recherche français pour vous proposer Science En Direct, deux jours de science non-stop gratuits et ouverts à tous !\n\nSous la houlette de Fred qui jouera les animateurs, venez rencontrer des scientifiques de tous les domaines, participer à des expériences ou répondre à des quizz, l’objectif principal étant toujours le même : apprendre en s’amusant !\n\nCa se passe les samedi 8 et dimanche 9 octobre 2016, de 10h à 18h (jusqu’à 19h le dimanche), à la Cité des sciences et de l’industrie (Forum d’Explora), en compagnie des instituts de recherche suivants :\n\nBRGM, CEA, CNES, CNRS, Genopole, Ifpen, Ifremer, Ineris, INRA, Inria, Inserm, IRD, Irstea, Météo-France et l’Université d’Évry-Val-d’Essonne.\n\nEt cerise sur le gâteau, c’est entièrement gratuit ! Retrouvez le programme complet des 2 jours (sous réserve de modifications de dernière minute).\n\n**>> À suivre en direct sur le web**\n\nEt si vous êtes loin de Paris, pas de problème : le week-end sera intégralement retransmis en direct sur [lespritsorcier.org](http://www.lespritsorcier.org/) ainsi que sur les sites des 15 instituts partenaires. Et on vous proposera par la suite l’essentiel en replay. Bref, aucune raison de ne pas participer avec nous à ce week-end qui s’annonce palpitant !\n\nN’hésitez pas à vous inscrire à [l’événement Facebook](https://www.facebook.com/events/1629115017402965/), et à faire passer le mot autour de vous et sur les réseaux sociaux via le hashtag [#ScienceEnDirect](https://twitter.com/search?src=typd&q=%23ScienceEnDirect). Incontournable, sur notre [chaîne Youtube](https://www.youtube.com/channel/UCH6rAZUDfVIoVSJjm3vlcnw)', 'fr', ', Esprit sorcier'),
(146717, 'Les abeilles et la pollinisation', 'Découvrez les formidables pollinisateurs que sont les abeilles.', 'La pollinisation est un service rendu par la nature aux hommes puisque 70% de la nourriture que l’on consomme dépends directement des pollinisateurs. Les abeilles sont les principaux pollinisateurs des cultures et leur diversité est bien plus importante que l’on croit. Tout le monde connaît l’abeille à miel... mais connaissez vous les 970 autres espèces qui vivent en France et qui sont très utiles à la pollinisation ?', 'fr', NULL),
(146718, 'La poterie comme à la Préhistoire', 'Démonstration de techniques', 'Frédéric Grosse, spécialiste du Néolithique, va montrer les différentes techniques de poterie en fabriquant devant le public une grosse jarre. Il présentera différents modèles et expliquera les innovations techniques et l''évolution des cultures.', 'fr', ',  Fabrication,  explications'),
(146719, 'Exposition "Architecture à Pommiers"', 'Petite exposition sur l’architecture ancienne et moderne à Pommiers ', 'Nous avons envie de montrer des constructions exemplaires du passé, des constructions plus récentes et aussi quelques images de l’extension de l’école élémentaire. En même temps il y aura la possibilité pour tous (enfants et adultes) de se lancer dans les constructions ludique, à petite échelle bien sûr.', 'fr', ',  exposition,  jeux'),
(146720, 'Concert de Jazz à Toulon !', 'Avec le quintet de jazz de la Musique des Equipages de la Flotte', 'C''est le Quintet de Jazz qui ouvrira la saison des concerts de la Musique des Equipages de la Flotte au Musée de la Marine de Toulon sur le thème de: "La Musique en noir et blanc" . Entrée : 4€50 sans réservation Renseignements au 04 22 42 02 01', 'fr', 'Musique des Equipages de la Flotte, Jazz, Concert, Toulon'),
(146721, 'Premier café citoyen à Bruxelles', 'Premier café citoyen à Bruxelles le mardi 11 octobre de 18h30 à 20h', NULL, 'fr', NULL),
(146722, 'Les grottes ornées du Gard', 'Conférence sur l''art pariétal ', 'Dans les Gorges du Gardon, la grotte de Baume Latrone abrite des peintures uniques, contemporaines de celles de la grotte Chauvet, soit plus de 36 000 ans. D''autres grottes recèlent aussi des témoignages de l''activité symbolique de nos ancêtres. Philippe Galant, préhistorien, (DRAC Occitanie), vous invite à les découvrir, à vous émouvoir devant ces peintures, ces signes dont pour certains nous ne connaîtrons jamais la signification.', 'fr', 'Art pariétal, Préhistoire, Gard'),
(146723, 'Test', 'test', NULL, 'fr', NULL),
(146724, 'La parure au Néolithique', 'Fabrication de parure comme à la Préhistoire', 'Les enfants vont découvrir les différentes parures ayant existé, leurs époques. Ils choisiront parmi des modèles présentés, celle qu''ils réaliseront avec de la stéatite mais avec les mêmes techniques et outils qu''au Néolithique. Après avoir tressé leur support, ils répartiront avec leur collier.', 'fr', 'Préhistoire, Parure, Art'),
(146725, 'Visite guidée "La main de l''Homme"', 'Découverte du nouveau parcours dans les salles de Préhistoire. Toutes les heures', 'A l''occasion de la Fête de la science, le Muséum ouvre au public le nouveau parcours de ses salles de Préhistoire intitulé La main de l''Homme : un voyage de plus de 500 000 ans dans l''histoire du département, de Homo erectus à Homo sapiens. L''évolution des représentants du genre Homo, la maîtrise du feu, la fabrication d''outils, leur mode de vie, l''art, la pensée symbolique… sont illustrés par les collections du Muséum dont la nouvelle statue-menhir. L''occasion de découvrir aussi la très longue histoire et riche histoire du l''agglomération nîmoise', 'fr', 'Préhistoire, exposition'),
(146726, 'SOIRÉE D''INFORMATIONS - bénévoles LSF', 'Participez aux activités LSF de Signes de sens ! ', 'Envie de participer aux activités LSF de Signes de sens ? (accueil du public, participation aux événements, animation, etc.)\n\n### **Et si vous deveniez bénévole ?**\n\nPour en savoir plus :\n\nRendez-vous **mardi 11 octobre à 18h30** au Mutualab à Lille !\n\nQue vous soyez sourd ou entendant… Que vous maîtrisiez la langue des signes ou non… On compte sur vous ! ', 'fr', 'bénévoles, lsf, langue des signes'),
(146727, 'Coding Club ', 'Découverte et apprentissage du code ', '## Apprendre à coder dès le lycée\n\nLes ateliers CodingClub permettent la découverte et l’apprentissage de la programmation, du code, et de tous les principaux langages informatiques.\n\nNous utilisons différents supports (Codecombat, scratch, unity3d pour les jeux…) ; les participants peuvent choisir des thématiques spécifiques (ex la cyber-sécurité) et différents formats (demi- journée, journée ou stages de vacances…) suivant les sites.\n\nDes groupes ont été créé sur Facebook qui permettent aux participants de suivre les évènements sur chacun des sites (12 villes, 12 groupes) et de dialoguer avec les étudiants animateurs de ces sessions.\n\n### Comment participer ?\n\nPour devenir membre du CodingClub Epitech, il suffit de s’inscrire sur le site codingclub.epitech.eu et de choisir l’école Epitech Nancy.\n\nLes formules sont diverses et dépendent des différents sites Epitech (stage vacances, sessions du mercredi ou du samedi après-midi)\n\nCes ateliers sont gratuits, animés par des étudiants d’Epitech\n\n**L''atelier aura lieu le samedi 22 et dimanche 23 de 10h00 à 17h00 au sein d''Epitech Nancy sur le thème ARDUINO et JEUX VIDEO.**\n\nAucune base n''est requise.', 'fr', ',   code week ,  arduino, jeux video'),
(146728, 'La Danse du Faucon', 'Exposition Photo', 'Les Robins des Bordes\n\n Invitent Bernard Carré, photographe \n\nA présenter :\n\n« La danse du faucon »\n\n(Paysages, faune et flore de la Plaine des Bordes)\n\nDu 22 Octobre au 28 Novembre 2016, à La Grange des Bordes\n\n127 rue des Bordes, Chennevières (94)\n\nVernissage le 22 octobre à partir de 17h\n\nSuivi du concert de Manu Lods (à partir de 20h30)', 'fr', NULL),
(146729, 'Peindre comme à la Préhistoire', 'Réalisation d''une fresque', 'Sur une paroi de grotte reconstituée, les enfants vont utiliser les mêmes techniques et les mêmes matériaux que les hommes et les femmes de la Préhistoire pour réaliser une grande fresque.', 'fr', 'Art, peinture, Préhistoire'),
(146730, 'Esquif', 'Spectacle cirque/musique avec Surnatural Orchestra/cie Inextremiste/cie Basinga', NULL, 'fr', NULL),
(146731, 'Vin et archéologie', 'À Gevrey-Chambertin, les opérations archéologiques menées entre 2006 et 2010, au lieu-dit au-dessus de Bergis, démontrent une occupation humaine récurrente de ce territoire.', 'Du Néolithique moyen au second Âge du fer, ce secteur du pied de la Côte de Nuits a été habité et cultivé, bien avant l’Antiquité.\n\ndimanche 9 octobre\n\n-Visite guidée à 14h30 : Beaucoup d’objets du musée reflètent l’importance du vin depuis l’époque de la dame de Vix jusqu’au 19e siècle... Par Félicie Fougère, conservatrice du Musée du pays Châtillonnais - Trésor de Vix\n\n- à 15h30 "Aux origines de la vigne à Gevrey-Chambertin (Côte-d’Or) : modes de plantation et de conduite de vignes antiques en bourgogne" par Sébastien Chevrier, archéologue à l''Inrap', 'fr', NULL),
(146732, 'Les Zones Humides en Bourgogne', 'Exposition au collège André Malraux à Dijon', 'l''association Bourgogne-Nature en partenariat avec le CCSTI Bourgogneprésentera son exposition sur les "Zones Humides en Bourgogne" associée à l''outil pédagogique Bourgogne-Nature junior n°5\n\n. De jolis panneaux colorés et illustrés offriront aux élèves de 5e et 6e et à leurs professeurs un regard attractif sur la nature et plus particulièrement une cartographie précise des zones humides de Bourgogne !', 'fr', NULL),
(146733, 'Découvrir les coulisses de la recherche archéologique', 'l''Inrap ouvre ses portes pour découvrir les coulisses de la recherche archéologique. ', 'Ce rendez-vous est l’occasion de découvrir les différentes facettes du métier d’archéologue et de comprendre le cheminement des vestiges, de leur découverte sur le chantier à leur étude au laboratoire…\n\nAu programme : visites, rencontres et animations autour des métiers de l’archéologie', 'fr', NULL),
(146734, 'Forum des acteurs culturels des vallées d''Aure et du Louron', '2e forum des acteurs culturels', 'Dans le cadre de la mise en réseau des acteurs culturels du territoire, coordonnée par le Pays d''art et d''histoire, le second forum des acteurs culturels se tiendra le samedi 22 octobre à 09h45 au centre culturel d''Ancizan. \n\nCe forum, non ouvert au public, est à destination de toutes les associations et structures culturelles des vallées d''Aure et du Louron.', 'fr', NULL),
(146735, 'Visites et animations au musée Paulin Ratier de Figeac !', 'Manipulations ludiques', 'Manipulations ludiques : analyse de la masse d''un système fermé ou ouvert, test avec mini-hélicoptère télécommandé, effet gyroscopiques.\n\nPour tout renseignement : 05 65 22 28 14', 'fr', NULL),
(146736, 'Une exposition sur le silicium et le quartz à Puy L''Évêque !', 'Exposition sur le silicium et la quartz', 'Pour les groupes, réservation au : 06 44 91 08 65 / cqst46@gmail.com', 'fr', NULL),
(146737, 'Visite architecturale "Ecole polyvalente Beaujon Monceau"', 'Le 14 octobre, à 15h30, le CAUE de Paris et la Direction du Patrimoine et de l’Architecture de la Ville de Paris vous invitent à visiter la restructuration de l’école polyvalente Beaujon Monceau', 'Découvrez lors d’une visite commentée, la restructuration de **l’école polyvalente Beaujon Monceau.** Ce projet, réalisé par l’agence **Ameller & Dubois Associés**, intervient dans le cadre de l’aménagement de la ZAC Beaujon, sur l’ancienne emprise de l’hôpital.\n\nCet équipement est divisé en deux lots, le premier comprend la construction d’une nouvelle école élémentaire, d’un pôle de restauration scolaire et de logements de fonction ; il a été livré en octobre 2015\\. Le second lot, toujours en chantier, concerne l’ancienne école élémentaire, transformée en école maternelle. L’école maternelle donnant sur la rue Monceau conserve de manière harmonieuse et cohérente l’apparence traditionnelle du bâtiment existant, un traitement homogène des autres façades favorise une perception en rapport avec les constructions environnantes. Ce projet est conforme aux normes HQE. \n\n**_Inscription obligatoire, possible jusqu''au mercredi 12 octobre, dans la limite des places disponibles._**\n\n**_Le port de chaussures fermées pendant la visite est obligatoire._**\n\n_Cette visite s''inscrit dans le cadre d''une série de visites d''équipements de la Ville de Paris sur le thème "Architectures de vos équipements publics" et de la première édition des journées nationales de l''architecture. _', 'fr', 'équipement public,   école,  visite architecturale, chantier'),
(146738, 'Présentation du projet d'' Assainissement des eaux usées adaptées au contexte Tropical par Traitement ExTensifs uTilIsant des VEgétaux', 'Permettre au public de toucher du doigt une étape clé du cycle consommation de l’eau et appréhender de nouvelles techniques de traitement des eaux usées dans le cadre du projet ATTENTIVE.', '**Contenu de l’animation :**\n\n1- Présentation du cycle de consommation,\n\n2- Explication du rôle et des différents types d’assainissement.\n\n3- Explication du fonctionnement d’une station à filtres plantés de végétaux.\n\n**Informations pratiques :**\n\n• Site : Station d’Epuration à filtres plantés de\n\nvégétaux de Taupinière au Diamant\n\n• Public visé : 4 classes de niveau collège et lycées et le grand public\n\n• Accueil des scolaires à raison de 30 min de visite environ par groupe, avec la collaboration des agents du SICSM.\n\n• Grand public : Journées portes ouvertes. Visite du site par petits groupes et mise en place de quizz avec lots à gagner pour les participants en fin de visite (selon disponibilités). Des agents du SICSM seront aussi présents sur site pour contribuer à l’animation.', 'fr', ',    Eau,   Martinique,   développement durable, assainissement'),
(146739, 'Découvertes des Métiers du CHU', 'Présentation des différentes métiers dans un CHU', 'Conférences sur la relation entre alimentation et cancer, alimentation et la vision, l’alimentation chez les personnes agées, présentation des différents métiers du CHU.', 'fr', NULL),
(146740, 'Visite architecturale "Ecole maternelle Torcy"', 'Rencontre entre les élèves de maternelle de l’école Torcy et l’architecte du bâtiment', '_Le 14 octobre 2016, le CAUE de Paris et la Direction du Patrimoine et de l’Architecture de la ville de Paris organisent une rencontre entre les élèves de maternelle de l’école Torcy et l’architecte du projet Anne Lavallois de l’agence Armand Nouvet._\n\nÀ l’occasion des journées nationales de l’architecture, les enfants de maternelle de l’école Torcy auront l''occasion de rencontrer l’architecte de leur école. Cette visite est une manière de les sensibiliser aux qualités architecturales de leur école, à leur environnement et de les amener à se questionner sur les espaces qui les entourent et sur leurs fonctions. Cette rencontre permet aussi de confronter le regard de l’architecte à celui des enfants, premiers usagers de l’école.\n\nL’organisation du bâtiment est directement issue de l’orientation Nord/Sud de la parcelle : on trouve au sud l’ensemble des locaux pédagogiques, alors que la façade nord accueille l’ensemble des locaux complémentaires. L’intérieur est en bois, immense tableau destiné à être personnalisé par ses usagers.\n\nL’école maternelle Torcy, livrée en 2016, a été réalisée par l’agence Armand Nouvet architecture et urbanisme pour la Ville de Paris. Le chantier de l’école élémentaire est toujours en cours.', 'fr', 'visite architecturale,   enfant,   école,   équipement public,  pédagogie, sensibilisation'),
(146741, 'La ressource sol, un avenir incertain !', 'Tout savoir sur les périls et le fonctionnement des sols', 'Les services que rendent les sols sont mis en péril par les usages que nous en faisons : érosion accélérée, pollution, surpâturage, perte des matières organiques, salinisation, artificialisation ou encore diminution de la biodiversité sont autant d’exemples qui menacent la ressource « sols ». Les sols sont pourtant essentiels pour notre alimentation et pourraient être un acteur clef de l’atténuation du réchauffement climatique. Au cours de cette conférence, nous verrons quelques éléments de compréhension du fonctionnement des sols, présenterons les différentes menaces qui pèsent sur les sols, et ferons le point sur les grands enjeux relatifs à cette ressource non renouvelable à l’échelle humaine.', 'fr', ''),
(146742, 'Randonnée géologique à Puy L''Évêque !', 'Randonnée géologique', 'Rendez-vous le Dimanche 16 octobre à 8h45 sur le parking de la Poste de Puy L''Évêque, départ à 9h.\n\nPour les inscriptions : 06 44 91 08 65 / cqst46@gmail.com', 'fr', NULL),
(146743, 'Migrations : regards croisés', 'Cycle de conférences consacrées aux migrations.', 'Dans le cadre de Louvain 2020, après une année académique consacrée aux utopies, l’UCL propose en 2016-2017 un cycle de conférences consacrées aux migrations. Elles offrent des regards croisés, interdisciplinaires, sur différentes thématiques transversales.\n\nUne dizaine de professeurs et leurs équipes de chercheurs en sciences humaines sont à l’origine de ce programme. Ils s’associent à des experts belges et internationaux pour informer, échanger et raisonner les questions que posent les migrations.', 'fr', 'Migration,   réfugiés,   famille,   violence,  santé,  récits'),
(146744, 'Biodiversité et big data', 'Conférence en anglais', '', 'fr', ''),
(146745, 'Un héritage de plomb', 'Cette conférence aborde l''utilisation pluri-millénaire du plomb et ses conséquences sanitaires sur les sociétés humaines.', 'Cette conférence aborde l''utilisation pluri-millénaire du plomb dans les sociétés humaines, ses bienfaits industriels et les conséquences sanitaires qui en résultent. L''exposition humaine aux sources très diversifiées de plomb est présentée dans un contexte historique depuis l''Antiquité jusqu''à nos jours.', 'fr', ''),
(146746, 'Littoral et fonds marins', 'Permettre la découverte scientifique de différents sites à partir d’un moyen de transport écologique qu’est le stand up paddle.', '**Informations pratiques :**\n\n• Niveau de difficulté : 2 (petite préparation physique souhaitable ; savoir nager)\n\n• Durée : 2h\n\n• Prévoir maillot de bain, protection solaire, masque et tuba, chausson\n\n• RDV à Grande Anse (Anses d’Arlet)\n\n• Renseignements et inscriptions : 0696 008 092', 'fr', ',    Padle,   Littoral,  Fonds marins, Martinique'),
(146747, 'La "curieuse visite curieuse" du Musée d''histoire de Figeac...', 'A Figeac, deux spectacles proposés par les musées de la ville.', 'Un comédien, accompagné d''un médiateur du musée, propose une visite décalée où se mêlent contenu scientifiques et historique à une part d''imaginaire de fantaisie, d''humour et de poésie. Ils vous feront (re)découvrir les fossiles, outils préhistoriques, tableaux et autres crapauds buffles qui composent les hétéroclites collections du musée d''histoire.\n\nRéservation recommandée : 05 65 50 31 08 / musee@ville-figeac.fr', 'fr', NULL);
INSERT INTO `${schema}` (`id`, `title`, `description`, `free_text`, `lang`, `tags`) VALUES
(146748, 'Jouez avec le système solaire', 'Jouez avec le système solaire, touchez-le du doigt, découvrez la diversité de ses planètes, planètes naines, satellites. Explorez la surface d''une comète. Imaginez d''autres mondes. ', 'Jouez avec le système solaire, touchez-le du doigt, découvrez la diversité de ses planètes, planètes naines, satellites. Explorez la surface d''une comète. Imaginez d''autres mondes. Calculez combien de planètes peuplent notre galaxie! Et même l''univers observable!\n\nDécouverte de la diversité des objets du système solaire (e.g. température, distance au soleil, taille, masse, obliquité de l''orbite, atmosphères, composition chimique) au travers de différentes activités possibles (reconstruire l''ordre des planètes, soupeser des maquettes à l''échelle de poids, observer des surfaces d''objets, deviner un objet céleste à partir de ses propriétés (jeu style "qui-est-ce") ou assister à la fabrication d''un modèle de comète.', 'fr', ''),
(146749, 'Débat public, concertation, conciliation, médiation : quelles synergies ? (8 novembre 2016)', 'Conférence-débat organisée par la CNDP, le Cnam et Médiations Plurielles, en association avec Démocratie et Participation, l''Institut de la Concertation et Décider Ensemble.', 'Alors que les processus de débat public et de concertation se sont largement étendus depuis 15-20 ans, la conflictualité est restée élevée dans le domaine de l''environnement et conduit à imaginer de nouvelles pistes de solutions pour renforcer le dialogue environnemental.\n\nUne des questions posées est celle des liens entre les différents processus de participation et de concertation, en amont de la décision, et du rôle que pourraient y jouer les approches de médiation et de conciliation, peu répandues encore dans notre pays. Il s’agira d’explorer les articulations possibles entre ces différentes pratiques et approches : A quelles situations répondent-elles ? Comment assurer entre elles une meilleure synergie tout en maintenant leurs spécificités ? Quels sont les liens entre les postures et les rôles de garant, de conciliateur, de médiateur et d''animateur de concertation ?\n\nPour plus d''informations, cliquez [ici](http://culture.cnam.fr/novembre/debat-public-concertation-conciliation-mediation-quelles-synergies--841401.kjsp).\n\nCet événement est une formation. Pour vous inscrire, contactez votre [chargé-e de formation](http://planet.loire-atlantique.fr/group/cg44/alize?p_p_id=alize_WAR_alizeportlet&p_p_lifecycle=0&p_p_state=normal&_alize_WAR_alizeportlet_url=http%3A%2F%2Fsso-planet-alize.loire-atlantique.fr%2Fjcms%2Fplanet_807957%2Fvos-contacts-pour-vous-inscrire-en-formation#p_alize_WAR_alizeportlet) du service emploi et compétences ou du service ressources.', 'fr', NULL),
(146750, 'A Luzech, portes ouvertes au musée "La Planète des Moulins"', 'Portes ouvertes', 'Découvrez de façon très concrète l''histoire de la domestication des énergies naturelles : humaine, animale, hydraulique et éolienne. Manipulez de nombreuses maquettes animées. Le musée vous propose une initiation par expérimentation de l''observation d''une riche collection des petits moulins domestiques ou artisanaux.\n\nRenseignements : 06 80 83 24 24 / [laplanetedesmoulins@wanadoo.fr](mailto:laplanetedesmoulins@wanadoo.fr)\n\nwww.museelaplanetedesmoulins.fr', 'fr', NULL),
(146751, 'Portes ouvertes "Venez ! Conseil architectural et paysager"', 'Conseil architectural et paysager', 'Le CAUE du Finistère ouvre ses portes à l’occasion des premières Journées nationales de l’architecture.\n\nConseil architectural gratuit > venez échanger sur votre projet avec les architectes du CAUE ! (sans rendez-vous)\n\nExposition > venez observer comment les architectes relèvent le défi de la transition écologique ! (visite commentée par des architectes)', 'fr', 'conseil,  architecture,  paysage,  urbanisme,  maison,  jardin, exposition'),
(146752, 'Conférence à Puy L''Évêque !', 'Conférence', 'Le silicium et le quartz dans le Lot, ses propriétés, ses applications.\n\nRenseignements : 06 44 91 08 65 / cqst46@gmail.com', 'fr', NULL),
(146753, 'Visite du Spectromètre de masse par Accélérateur ASTER', 'L’instrument national ASTER (Accélérateur pour les Sciences de la Terre, Environnement, Risques) et ensemble des périphériques permettant l’analyse des nucléides cosmogéniques.', 'Aster? Non ce n''est pas une fleur mais un accélérateur de particules qui vous est présenté. Cet appareil permet non seulement de séparer les atomes en fonction de leur masse mais aussi de compter les atomes un à un! A partir de quelques grammes de roche, Aster permet de répondre à de nombreuses questions environnementales : Combien de temps faut il pour créer un relief? A quelle vitesse bougent les failles tectoniques? A quelle époque les glaciers ont ils fondu? Quel est l''âge de notre ancêtre Toumaï?\n\n[http://www.cerege.fr/spip.php?article135](http://www.cerege.fr/spip.php?article135)\n\nCette visite de laboratoire s''inscrit dans le dispositif "[Labos si j''y suis](http://cps.univ-amu.fr/labos-si-jy-suis)" d''Aix-Marseille Université.', 'fr', ''),
(146754, 'Fête de la science au Muséum', 'les scientifiques vous attendent pour trois jours d''immersion dans le monde des drogues, poisons et autres toxiques.', 'Cette année, un nuage toxique recouvre le Muséum le temps de la Fête de la science, mais pas de panique, nous disposons des antidotes ! Découverte des plantes toxiques et pourtant utiles à la médecine, des champignons vénéneux et des animaux venimeux à éviter, propagation des épidémies, résistance aux agents pathogènes, fonctionnement des capteurs de molécules toxiques, déchiffrage des étiquettes des produits ménagers ou dangereux… Les scientifiques vous attendent pour 3 jours d''immersion dans le monde des drogues, poisons et autres toxiques.', 'fr', 'toxique, poison, plante, épidémie, champignon, venin, muséum'),
(146755, 'Exposition "La maison écologique de demain"', 'Exposition d’architecture', 'L’aménagement du nouveau quartier Saint-Philibert sur la commune de Plomelin (29) est le support d’un concours d’idées pour imaginer une maison écologique, économique, susceptible de s’agrandir au fil des besoins et pouvant s’implanter avec souplesse sur différentes configurations de terrains.\n\nCette exposition présente les 35 projets de la première phase du concours. A partir du 14 octobre seront présentés les 20 projets finalistes sous la forme de panneaux et de maquettes.\n\nOrganisateur : SAFI/commune de Plomelin\n\nPartenariat : Conseil départemental, agence TLPA et CAUE 29.', 'fr', ',     exposition,    architecture,   concours d''idée,  maison écologique, maison économique'),
(146756, 'Visite du Microscope Electronique à Balayage', 'Visite du Microscope Electronique à Balayage', 'Pour observer au MEB, les micro-organismes calcaires qui vivent dans l’océan et que l’on retrouve dans les sédiments océaniques. Les chercheurs utilisent ensuite ces micro-organismes (les foraminifères par exemple) pour reconstituer les climats passés.\n\nCette visite de laboratoire s''inscrit dans le dispositif "[Labos si j''y suis](http://cps.univ-amu.fr/labos-si-jy-suis)" d''Aix-Marseille Université.', 'fr', 'Paléoclimatologie, MEB'),
(146757, 'Visite de la plate forme de spectrométrie de masse', 'Visite des spectros de masse par thermo-ionisation et multi-collecteur ICP MS', 'Cette visite de laboratoire s''inscrit dans le dispositif "[Labos si j''y suis](http://cps.univ-amu.fr/labos-si-jy-suis)" d''Aix-Marseille Université.', 'fr', 'géochimie, TIMS, MC ICP MS'),
(146758, 'Voyage au coeur d’un volcan strombolien', 'Randonnée découverte de la Savane des Pétrification sur la plateforme d’usure d’un ancien volcan strombolien.', '**Informations pratiques :**\n\n• Cible : Grand public uniquement\n\n• Niveau de difficulté : 1 (accessible à tous)\n\n• Durée : 3h\n\n• RDV à Grande Terre au niveau de la barrière, après la Grande Anse des Salines\n\n• Prévoir de bonnes chaussures de marche, une casquette ou un chapeau, une tenue de randonnée\n\n• Renseignements et inscriptions : 0596 705 488 ou 0696 308 170', 'fr', ',    Randonnée,   Savane des pétrification,  Volcan, Martinique'),
(146759, 'Présentation Novadem', 'Novadem est spécialisée dans la robotique aérienne ( UAV, drone ). Elle conçoit et réalise des drones de faible envergure destinés aux marchés civils et miltaires.', '[Novadem](http://www.novadem.com) est spécialisée dans la robotique aérienne ( UAV, drone ). Depuis 2006, elle conçoit et réalise des drones destinés aux marchés civils et militaires. Véritable pionnier des micro-drones Français, ses projets de recherche et développement sont soutenus par le ministère de la recherche ainsi que les acteurs régionaux et nationaux de l''innovation. La société est lauréate du concours national d''aide la création d''entreprises de technologies innovantes 2006 et 2007.\n\nCette action s''inscrit dans le cadre de l''action "[Labos si j''y suis](http://cps.univ-amu.fr/labos-si-jy-suis)" d''Aix-Marseille Université.', 'fr', ''),
(146760, 'Vivre autrement', 'Canopé en partenariat avec l''AME, animera des ateliers dans les écoles dont la thématique portera sur l’énergie solaire.', 'Dans le cadre d’un partenariat avec l’agence martiniquaise de l’énergie (AME), Canopé souhaite animer des ateliers dans les écoles dont la thématique portera sur l’énergie solaire. Des ressources et des outils du réseau (les énergivores) viendront compléter la connaissance autour de l’énergie solaire et des autres énergies durables. Un appel à candidature sera lancé dans les écoles et établissements scolaires une semaine avant la Fête de la science.\n\n**Informations pratiques :**\n\n• Cible : élèves du Primaire et collégiens\n\n• Type d’opération : Interventions en milieu scolaire', 'fr', ',    Canopé,   AME,  Energie solaire, Martinique'),
(146761, 'Speed dating des métiers de l''environnement', 'Découvrez les métiers de l''environnement !', '', 'fr', 'Niveau de la mer, activité humaine, circulation thermohaline, changement climatique'),
(146762, 'Civic tech et Community organizing (10 novembre 2016)', 'Séminaire organisé par le réseau DEL et Démocratie ouverte', 'Le mouvement Civic tech, qui vise à mobiliser les citoyens via des outils numériques pour prendre part à l''activité démocratique, connait actuellement un engouement très important. Il soulève de nombreux espoirs en termes de mobilisation citoyenne et de transformation démocratique. Pourtant, il importe de ne pas se laisser emporter par "l''effet nouveauté" et réfléchir à la manière d''accompagner ces initiatives au-delà du stade expérimental.\n\nDans ce cadre nous proposons de poser les bases d''une démarche comparative avec un autre mouvement, le community organizing. Ce mouvement qui mobilise des citoyens pour agir dans leur environnement direct depuis plus de 20 ans s''est confronté à un certain nombre de problèmes (indépendance, institutionnalisation, capacité à s''inscrire dans des rapports de force...) qui se pose (ou se poseront également aux Civic tech. Quelles ont été les réponses apportées ?\n\nPour plus d''informations, cliquez [ici](http://institutdelaconcertation.org/wakka.php?wiki=AgendA&vue=consulter&pageID=1).\n\nCet événement est une formation. Pour vous inscrire, contactez votre [chargé-e de formation](http://planet.loire-atlantique.fr/group/cg44/alize?p_p_id=alize_WAR_alizeportlet&p_p_lifecycle=0&p_p_state=normal&_alize_WAR_alizeportlet_url=http%3A%2F%2Fsso-planet-alize.loire-atlantique.fr%2Fjcms%2Fplanet_807957%2Fvos-contacts-pour-vous-inscrire-en-formation#p_alize_WAR_alizeportlet) du service emploi et compétences ou du service ressources.', 'fr', ', participation citoyenne'),
(146764, 'La Supplication. Un film de Pol Cruchten', 'Une transposition inspirée et poignante du livre écrit par Svetlana Alexievitch, prix Nobel de littérature 2015, à partir des récits de victimes de la catastrophe de Tchernobyl.', '**Dans le cadre de la Quinzaine du cinéma francophone**\n\nCe film ne parle pas de Tchernobyl, mais du monde de Tchernobyl dont nous ne connaissons presque rien. Des témoignages subsistent : des scientifiques, des enseignants, des journalistes, des couples, des enfants, ... Ils évoquent ce que furent leur quotidien, et puis la catastrophe. Leurs voix forment une longue supplication, terrible mais nécessaire qui dépasse les frontières et nous amène à nous interroger sur notre condition.\n\n_Luxembourg/Autriche – 2016 – 1 h 26_\n\nScénario : Pol Cruchten, d’après le roman de Svetlana Alexievitch, Prix Nobel de Littérature 2015\\. Avec : Dinara Drukarova, Iryna Voloshyna, Vitaliy Matvienko, avec les voix de Camille Saltet de Sablet, Marc Citti, Eric Caravaca, Laurence Côte, Salomé Stévenin, Robinson Stévenin.\n\nGrand Prix du Festival international du Film d’environnement de Paris 2016, Grand Prix au Festival international du film de Saint-Paul, Minneapolis 2016\\. Ce film représente le Luxembourg à l’Oscar du film étranger 2016.', 'fr', NULL),
(146765, 'LFT x GD PRESENTS SEVERED HEADS', 'Musiques Electroniques', 'Severed Heads s''est formé en 1979 à Sydney. Véritables pionniers de la musique électronique ayant eu, pour certains, autant d''influence que Kraftwerk. À l''avant-garde sur les différentes techniques de productions et de compositions de l''époque, ils ont également été précurseurs dans l''usage de la vidéo.\n\nLeur discographie abondante s''étend des sons électroniques dissonants des débuts, à leur phase pop plus tardive.\n\nDe passage en Europe dont l''Unsound Festival (Cracovie) et Berlin, ils feront un détour par Paris pour un live exclusif.\n\nLe reste de la soirée sera confié à Moyo, boss du label Mind Records, Jan Melnick, cofondateur et DJ de La Fête Triste et Quick Culture et Mu''tammar, duo composé par Gorka Seguy (LFT-Seconde Zone) et Romain Mascagni (Dscrd).', 'fr', 'Severed Heads, Le Chinois, Montreuil'),
(146766, 'Jean Muller, Récital de piano', '"Idées claires, jeu ample s’adaptent à toutes les périodes et tous les styles avec une facilité qui ne laisse à aucun moment deviner l’important travail que suppose une telle aisance." EM/Diapason', '_Dans le cadre du festival Autour du Piano_\n\n**Programme**\n\nBrahms : Sonate op. 1 n°1\n\nBoumans : Barcarolle n°3\n\nLigeti : «arc-en-ciel» - «escalier du diable»\n\nProkofiev : Sonate n°6\n\nLe pianiste Jean Muller est un artiste connu pour son authenticité artistique. Salué comme un «talent majeur» par le magazine Gramophone, il a étudié à Bruxelles, Munich et Paris. Jean Muller a remporté douze premiers prix lors de concours internationaux. Il a joué avec de nombreux ensembles dont l''Orchestre d''État de Bavière, L''Orchestre symphonique de Munich et l''Orchestre Philharmonique du Luxembourg. Après une tournée internationale couronnée de succès avec son programme de de récitals Chopin en 2013, Muller a lancé le projet Transcendance en 2014 avec une tournée mondiale et l’enregistrement des Etudes Transcendantales de Liszt et de la Mephisto-Valse No. 1 dans la version éblouissante de Vladimir Horowitz. Jean Muller vient d''être nommé directeur artistique de l''Orchestre de Chambre du Luxembourg à partir de la saison 2016/2017.', 'fr', NULL),
(146767, 'DIANE CANOBY + NINA BLUE', 'Folk, Blues', 'DIANE CANOBY\n\nUn timbre de voix unique, des mélodies folk/rock enveloppantes, intenses et envoutantes qui font lien entre la terre, le sacré, le ciel et l''univers...\n\nFacebook : www.facebook.com/canobydianeSoundcloud : https://soundcloud.com/diane-canobyVimeo : https://vimeo.com/170210782\n\nNINA BLUE\n\nUn trio atypique, une voix puissante, des textes poétiques et engagés en anglais, français et arabe. Des influences blues/trip hop… une invitation au voyage.\n\nFacebook : www.facebook.com/NinaBluesbandSoundcloud : https://soundcloud.com/nina-blue-s-bandYoutube : https://youtu.be/KyxtJDZv8a0', 'fr', 'Le Chinois, Gratuit, Montreuil'),
(146768, 'Chèvrefeuille, sauras-tu garder tes arbres et ton troupeau ?', 'Le Laboratoire Population-Environnement-Développement vous propose de découvrir la notion de gestion forestière raisonnée autour d’un jeu d’apprentissage du développement durable. ', 'Lors de cette animation, vous serez invité à vous mettre dans la peau d’un éleveur devant répondre aux besoins alimentaires de son troupeau. Vous disposerez alors d’une exploitation d’arbres fourragers, première source alimentaire du troupeau. L’objectif du jeu sera d’assurer son alimentation sur une période de dix années grâce à une exploitation raisonnée des arbres fourragers présents. Saurez-vous garder vos arbres et votre troupeau ? Quelle stratégie adopterez-vous face aux aléas climatiques que vous rencontrerez ?', 'fr', ''),
(146769, 'Dock In Absolute au Festival Jazz à la Cité', 'Dock In Absolute est un savant mélange de Jazz Electra teinté d''une saveur classique, alliant l''accessibilité émotionnelle et intuitive de la pop et du funk à l''univers des musiques de film... ', '**David Kintziger** (contrebasse) **Jean-Philippe Koch** (piano) **Michel Meis** (batterie)\n\nDock In Absolute, c’est l’heureuse rencontre de trois musiciens de talent ayant étudié au Berklee College of Music de Boston, à la Codarts University of Arts de Rotterdam et à la Hochschule für Musik de Saarbrücken : David Kintziger (contrebasse) Jean-Philippe Koch (piano et composition) et Michel Meis (batterie).\n\nDock In Absolute peut se définir comme un savant mélange de Jazz Electra teinté d''une saveur classique dans l''écriture, alliant l''accessibilité émotionnelle et intuitive de l''univers musical pop-rock et funky à celui de la musique de film... Une manière douce d’amener le public à s’ouvrir et oser de nouveaux genres musicaux ! Dock In Absolute a déjà de nombreux concerts et festivals  à son actif dont le Hong Kong International Jazz Festival, le Beishan Festival, le Brussels Jazz Marathon, le Blues’n Jazz Rallye et le Blues Express au Luxembourg, Jazzit Fest à Turin, B Flat à Berlin, International Jazz Festival à Sibiu, Stuttgart International Jazz Festival, Glaze Zaal à Lahaye,  Like a Jazz Machine International Jazz Festival, Luxembourg ainsi qu’une tournée en Chine et au Canada.', 'fr', NULL),
(146770, 'Forum des patrimoines culturels : "Autour de Boris Ziwès, architecte de la départementalisation en Guyane (1951-1976)"', 'Présentations sur le parcours de Boris Ziwès, 1er architecte départemental de Guyane, la fonction d''architecte du Conseil général et un exemple d''architecture moderniste en cours de réhabilitation.', 'Le Forum des patrimoines culturels organisée par la Collectivité territoriale de Guyane a pour objectif de présenter et de restituer au public les travaux de recherche de l''Inventaire général du patrimoine culturel.\n\nLe service Langues et Patrimoine en charge des missions d''Inventaire général a initié un inventaire thématique sur l''architecture moderne ou moderniste en Guyane, qui s''est particulièrement développée avec la départementalisation intervenue en 1947 et constitue un patrimoine important dont les institutions commencent à prendre conscience.\n\nPour répondre aux besoins en logement et en infrastructures publiques, de nombreux édifices sont construits dans les années 1950-1960 dans un style nouveau où le béton armé prend une place dominante sur les matériaux traditionnels qu''étaient le bois et la brique. De nouveaux volumes, de nouvelles lignes se dessinent, tout en s''inspirant de l''architecture créole.\n\nParmi les acteurs de ce mouvement architectural, la figure de Boris Ziwès (1913-1976), arrivé en Guyane en 1951, est prépondérante. Il exerça tant pour le Département naissant qu''au sein d''un cabinet privé dans toutes les communes de Guyane. On lui doit de nombreux équipements publics. Il s''est également investi dans le logement social par le biais de maisons-type, reconnaissables à leurs pilotis en béton et leur structure en bois (maisons Urubu).\n\nLe Forum des patrimoines culturels s''attachera à présenter le parcours professionnel de cet architecte, la mission d''architecte du Département jusqu''à la création de la Collectivité territoriale de Guyane en 2016 et un exemple de réhabilitation en cours d''un édifice scolaire dessiné par Boris Ziwès.', 'fr', ', Boris Ziwès ; architecte départemental ; architecture moderne ; réhabilitation'),
(146771, 'BRAND NEW HATE + DICK TRACY LORDS + THE TRUE FAITHS', 'High Energy Rock', 'Concert Rock''n Roll / Punkrock avec\n\n• Brand New Hate (RnR - Saint Etienne)www.facebook.com/brandnewhatehttp://brandnewhate.bandcamp.com/\n\n• Dick Tracy Lords (Hi-Energy RnR - Paris)www.facebook.com/dicktracylordswww.dicktracylords.com/\n\n• The True Faith (Hi-Energy RnR -Paris)\n\nLe Vendredi 21 Octobre à L''Olympic Café, 20 rue Léon, Paris 18ème20 h - 6 €', 'fr', 'Olympic, Barbès'),
(146772, 'Présentation de L’Atelier de la comète - Bureau mobile d''architectes, paysagistes et scénographes basé à Rennes ', 'L’Atelier de la comète architectes et paysagistes', 'Lancé en 2014 à Rennes, l’Atelier de la comète propose ses compétences d’explorateurs spatiales aussi bien en paysage qu’en architecture. Il est composé de deux architectes diplômés d’État.\n\nE.Métrard s’est formé en France et au Brésil. Il a une expérience en agences d’architecture qui lui a permis d’obtenir l’Habilitation à la Maîtrise d’Oeuvre en son Nom Propre (HMONP). Ses compétences sont élargies par une formation spécifique au paysage.\n\nA.Alanou s’est formé en France et en Chine. Il est ensuite parti pendant 2 ans à Ouarzazate au Maroc comme responsable de la spécialité décors et accessoires d’une école de cinéma (ISMC). Ses compétences acquises en agences et son parcours de scénographe apportent un autre regard au projet.\n\nL’Atelier conjugue architecture, paysage et scénographie pour questionner les lieux dans une approche où bâti, végétal et mise en scène ne font qu’un.\n\nhttps://atelierdelacomete.wordpress.com/', 'fr', ',     architecte,    scénographe,   paysagiste,  bureau mobile, Rennes'),
(146773, 'Pollens et insectes fossiles', 'L''IMBE vous propose de découvrir les pollens et insectes fossiles et leur utilisation en sciences de l''environnement.', '', 'fr', ''),
(146774, 'Découverte des hydrosystèmes', 'A travers une maquette géante, découvrez comment se forment les rivières !', '', 'fr', ''),
(146775, 'Quels sont les moteurs de la circulation océanique ?', 'Venez reconstruire la circulation thermohaline dans un aquarium !', 'Comprendre la circulation océanique, son origine et son importance pour le climat. Découverte des principes de base de l''océanographie et atelier pratique modélisation de l’océan dans un aquarium.', 'fr', ',    océan,    courant océanique,   transport de chaleur,  modélisation'),
(146776, 'Les invasions biologiques : quels mécanismes ?', 'Présentation du groupe de travail COREIDS du CESAB', 'Prédire la résilience des communautés face aux invasions, selon la diversité et la structure des réseaux d’interactions : tel est l''objectf du projet [COREIDS](http://www.cesab.org/index.php/fr/projets-en-cours/projets-2012/88-coreids) : \n\nhttp://www.cesab.org/index.php/fr/projets-en-cours/projets-2012/88-coreids', 'fr', 'Niveau de la mer, activité humaine, circulation thermohaline, changement climatique'),
(146777, 'En route pour le Mondial', 'Séjour thérapeutique autour du Mondial 2017 de Handball', 'Dans le cadre de ses activités, le Club de la Pierre de Lune, association d''usagers de la Santé Mentale, organise un séjour à visée thérapeutique autour du championnat du monde de Handball 2017\\. Celui-ci aura lieu du 20 au 24 janvier 2017 à Brélès et ce dans le but d''assister aux 8 matchs de la Coupe du Président. Ce projet a été initié par des personnes impliquées dans une démarche de soins et le groupe se composerait de 2 soignants et 7 soignés.', 'fr', NULL),
(146778, 'Sonic Trip sur Aligre Fm 93.1', 'dans le cadre du festival Bar-Bars', 'Emission « Sonic Trip » Emission de Rock, sur Aligre fm 93.1\n\nEnregistrement public le Samedi 26 novembre à 18h (et diffusion le mardi 29 à 19h30).\n\nCréée en 1993 sous le nom de Substitute, Sonic Trip nous plonge chaque semaine dans l’histoire et l’actualité du rock de ses origines à nos jours.\n\nL’émission a une dimension internationale et l’on voyage de Detroit à Sydney en passant par New York, Madrid, Paris, Londres ou Stockholm, Marseille ou Melbourne.\n\nDu rock sans concession ni chapelle sous toutes ses formes, en mettant aussi l’accent sur toutes les musiques qui l’inspirent ou l’influencent.\n\nPrésentée par Isabelle Konopnicki, Eric Pouille, Franck Durand et Bernard Ganchou.\n\n[http://aligrefm.org/](http://aligrefm.org/)\n\n[https://www.facebook.com/groups/187095991352/#!/groups/187095991352/](https://www.facebook.com/groups/187095991352/#!/groups/187095991352/)', 'fr', 'enregistrement public'),
(146779, 'Parcours botanique', 'A travers le plateau de l''Arbois, venez découvrir la diversité botanique de la forêt méditerranéenne', '', 'fr', ''),
(146780, 'Le système solaire', 'Un parcours et quizz sur le système solaire', '', 'fr', ''),
(146781, 'Village des sciences de Saint-Nazaire', 'Forum d’animations et d’expérimentations', 'Le Village des sciences est un forum d’animations et d’expérimentations rassemblant, sur plusieurs jours, des spécialistes du monde scientifique. Les acteurs du Village des sciences de Saint-Nazaire éclaireront, à votre attention, la science, ses métiers et ses applications.', 'fr', 'nature, monnaie, compost, déchet, algues, salon république'),
(146782, 'Débat "Plateforme de la création architecturale saison 4"', 'Philippe Rahm, Paris versus Didier Fiúza Faustino, Paris', 'Principe d’un face-à-face trimestriel entre deux équipes d’architectes, l’une exerçant en France, l’autre dans un pays européen. La confrontation se développe d’abord sur un « meuble » en forme de half-pipe, également partagé entre les deux équipes, chacune  y mettant en scène librement objets, documents audiovisuels, dessins, maquettes de son choix…\n\nDeux écrans prennent le relais dans l’espace contigu, avec un film de synthèse d’une vingtaine de minutes sur la démarche des deux équipes, élément pour un débat en public entre les protagonistes de ce face-à-face.\n\nChaque saison est marquée par une série d’événements qui se tiennent dans le nouvel espace « Débats » de la Cité de l''architecture & du patrimoine : en ouverture de la saison, débat entre les deux équipes mené par un critique invité, puis deux soirées à l’initiative des architectes.', 'fr', 'faustino, rahm, architecture, plateforme, design, art, logement, plateforme, création, cité de l''architecture, architecte'),
(146783, 'Village des sciences d''Angers', 'Village des sciences d''Angers', NULL, 'fr', NULL),
(146784, 'Village des sciences de Saumur', 'Village des sciences de Saumur', NULL, 'fr', NULL),
(146785, 'Exposition "Les architectures de Villeneuve d''Ascq par quartier"', 'exposition photographique présentant un extrait du guide par quartier des architectures de Villeneuve d''Ascq réalisé par le laboratoire de recherche de l''ensapLille', 'Parution juillet 2016\n\nTextes de Catherine Blain et Richard Klein (Lacth/Ensapl).  Photographies de Pierre Thibaut (région Hauts-de-France - Nord Pas de Calais - Picardie) Ce guide est constitué de deux entités distinctes : . un livret illustré de 60 pages, agrafé, où sont présentés 146 réalisations emblématiques de Villeneuve d''Ascq, au fil de ses 17 quartiers; . une carte dépliante de la ville, format 60x90cm détachable, sur laquelle sont répertoriées les 146 réalisations détaillées dans le livret.   © Editions de l''Ensapl, 2016 ISBN 978-2-90-586530-4 Imprimé sur les presses de l''imprimerie Monsoise, à Mons-en-Baroeul (France).', 'fr', NULL),
(146786, 'Conférence "PrintArch - Impression 3D pour l''architecture"', 'Challenges PrintArch sur la thématique de l''impression 3D pour l''architecture. ', 'Lancement des challenges PrintArch sur l''impression 3D pour l''architecture. \n\nLa rencontre propose une série de présentations sur les enjeux de la fabrication additive et de la fabrication robotisée pour l''architecture. \n\nDe plus nous présenterons les challenges Printarch : Thématiques, déroulements et attendus.\n\nPlus d''information : [http://www.printarch.net](http://www.printarch.net)', 'fr', 'impression 3D, défi, innovation, challenges numériques, architecture'),
(146787, ' Architectures habitées de l''Ile de Nantes 2010-2016 ', 'Exposition du 7 octobre au 17 décembre 2016 - Du mardi au samedi de 13h à 19h ', 'L''île de Nantes connaît une forte dynamique de projets depuis le début des années 2000.\n\nLa Samoa, maître d''ouvrage, et l''équipe d''architectes urbanistes Smets/uapS, a instauré depuis 2010 une nouvelle approche qui tisse une attentive relation entre projet urbain et architecture, notamment à travers les questions d''usages et de mixités.\n\nL''exposition "Architectures habitées de l''île de Nantes 2010-2016" présente le processus de conception des projets lancés sur la période et les ambitions de leurs différentes expressions architecturales.\n\n_Pour enrichir cette exposition, un programme de visites et de rencontres est proposé par l''Agence des rencontres urbaines :_\n\n_- Samedi 15 octobre, de 9h30 à 12h : "Explo, dérive à travers l''Ile habitée"_\n\n_- Lundi 17 octobre, de 18h à 19h30 : "A la découverte d''une agence d''architecture"_\n\n_- Jeudi 27 octobre, de 18h à 19h : "Rencontres avec les nouveaux acteurs de la maîtrise d''usage"_\n\n_- Jeudi 24 novembre, de 11h30 à 13h : "Rencontre avec les acteurs d''un chantier"_\n\n_- Jeudi 8 décembre, de 12h30 à 14h : "L''ile Bus Tour"_\n\n_Visites et rencontres sur inscription :_\n\nENTREE LIBRE', 'fr', 'visite, exsposition, rencontres'),
(146788, 'Raging Fyah - Stick Figure au Réacteur', 'Soirée reggae avec le Réacteur !', '**Raging Fyah,** ou le feu qui fait rage en jamaïcain. Un feu généreux, chaleureux et à la musique absolument envoûtante. Servi par la voix exceptionnelle du frontman Kumar Bent. Raging Fyah compte parmi les groupes majeurs ayant permis un renouvellement de la planète reggae ces dernières années. A mi chemin entre reggae roots traditionnel et influences soul, blues et rock, le combo jamaïcain s’est affirmé comme un des groupes les plus influents du moment. Après deux premiers albums acclamés et plusieurs tournées à succès, le groupe revient avec un tout nouvel opus intitulé Everlasting. Un disque bourré de hits aux textes conscients, passionnés et universels. Et comme si cela ne suffisait pas, le groupe aime la scène et en fait son tremplin en offrant des concerts passionnés d’une générosité rare. Et à l’occasion de leur tournée européenne, ils nous font le plaisir de faire une date exclusive au Réacteur !\n\n[https://www.youtube.com/watch?v=DN9j0frIhmo](https://www.youtube.com/watch?v=DN9j0frIhmo) \n\n**Invités spéciaux : Stick Figure**\n\nDes grooves caverneux, des orchestrations électroniques brillantes et des rythmiques épaisses, voilà la recette du succès de Stick Figure, combo reggae et dub emmené par son leader et compositeur Scott Woodruff. Accompagné d’une fraternité de musiciens aguerris, il délivre ses vibrations au cours d’un live qui prend la forme d’une véritable performance appelant les consciences à l’émancipation. Les concerts de Stick Figure se distinguent par de longs interludes improvisés et une communication avec le public sans pareil. Adulé outre atlantique, le groupe entame sa première tournée européenne et réserve au Réacteur sa toute première date en région parisienne !\n\n[https://www.youtube.com/watch?v=U9_6XFcRoGM](https://www.youtube.com/watch?v=U9_6XFcRoGM)', 'fr', 'reggae, rock, concert, issy, bob marley, groundation'),
(146789, 'Le Handball Partout et pour Tous à Toulouse', 'Partager les valeurs de respect, de solidarité et de plaisir avec d''autres jeunes qu''on ne connaît pas', 'A travers, la pratique du handball, les jeunes pourront partager des moments conviviaux qui où se mêlent le Partage, la bonne humeur, la convivialité et le respect de chacun.\n\nLa caravane du handball est un outils pédagogique qui aidera les éducateurs du Fenix Toulouse Handball à s''occuper des jeunes de 9 à 16 ans des différents quartiers du Mirail (Reynerie, Bellefontaine, Farouette...).\n\nLes jeunes pourront réaliser diverses animations handballistiques (Tirs, ateliers de motricité, tournoi de hand, notion d''arbitrage...) mais seront également interrogé via un questionnaire sur les Valeurs du Sport en relation avec les valeurs de la République.', 'fr', 'Plaisir,  Respect,  Partage, Tolérance'),
(146790, 'Carpenter Brut - Noise Generator au Réacteur !', 'Soirée Electro-rock', 'Assister à un concert de **Carpenter Brut** c’est partir pour un voyage lointain à la croisée des influences. Comme si l’on organisait une soirée ou l’on invitait Kavinsky, Giorgio Moroder et Ghost pour regarder ensemble des films d’horreur des années 80\\. Car oui, Carpenter Brut donne à écouter mais aussi à voir à travers un show visuel époustouflant nous transportant dans l’univers des séries Z et autres films gores des décennies passées. Entouré de mystère et de discrétion, l’homme derrière le pentagone explique qu’il s’agit d’une rencontre entre les beats de Justice et l’univers de John Carpenter. Mais quelles que soient ses sources, Carpenter Brut ne manque jamais de talent pour composer d’imparables tueries vintage qui n’ont que faire des barrières et des concepts établis. Après avoir appris par cœur l’album Trilogy regroupant leurs trois premiers EP, venez prendre la claque du moment en live au Réacteur !\n\nSur le net : [https://www.facebook.com/carpenter.brut](https://www.facebook.com/carpenter.brut)\n\nDuo parisien d’électro-punk, le projet **Noise Generator** est emmené par deux routards bien connus de la scène alternative : Laurent (ex Charge 69) et Kshoo (ex Dirty District Boost et Noxious Enjoyment). A coup de guitares, synthétiseurs et autres beats aux influences multiples, la musique de Noise Generator nous emmène dans un univers éclectique et terriblement efficace. Découvrez sans plus attendre leur dernier disque « Warning », une pépite groovy et métallique qui achèvera de vous convaincre de venir les découvrir en live au Réacteur !\n\nSur le net : [https://www.facebook.com/NOISEGENERATOR.officiel](https://www.facebook.com/NOISEGENERATOR.officiel)\n\n[https://www.youtube.com/watch?v=er416Ad3R1g](https://www.youtube.com/watch?v=er416Ad3R1g)\n\n►Ouverture : 19h00\n\n►Tickets : 14€ en prévente / 16€ sur place\n\n►Bar sur place', 'fr', 'electro, rock, carpenter brut, justice, carpenter'),
(146792, 'Mondialito à Poissy', 'Tournoi scolaire ', 'Suite à la présentation du projet, le service des sports avec le service éducation a mis en place dans toutes les classes de CM1 - CM2 de toutes les écoles de la commune de Poissy, un cycle handball au retour des vacances de la Toussaint.\n\nLe club entre dans cette démarche par la mise à disposition de matériel et d''une personne diplômée.\n\nLors d''une présentation officielle avant les vacances de la Toussaint, chaque classe connaîtra le nom du pays qu''il représentera. En présence du Maire, un tirage au sort aura lieu avec l''ensemble des enseignants et des responsables service éducation et service des sports.\n\nLes poules seront exactement les mêmes que celles du mondial 2017\\. Tout le tournoi aura lieu le vendredi 23 juin.\n\nCependant durant l''année, les enfants vont pouvoir de manière transversale étudier leur pays, composer des exposés pour l''école, découvrir le handball. De plus, sur les temps péri-scolaire un atelier hand est mis en place dans les écoles (en rotation) sur toute l''année.', 'fr', 'Handball, Ecole, mixité'),
(146793, 'MAN ANAM KE ROSTAM BOVAD PAHLAVAN création 2016 @ New Settings TCI', 'Concept: Ali Moini Interprétation: Ali Moini Scénographie: Julien Peissel + Ali Moini Machinerie: Julien Peissel Lumière: Stéfane Perraud Compositeurs: Sarah Bigdelishamloo & Nima Aghiani ', '"_Face à face, Ali Moini, glissé dans un vêtement relié par des mousquetons et des poulies à un système complexe de fils, et une marionnette en métal se toisent. Chaque mouvement du danseur est répercuté par le pantin qui en donne une version chaotique et démantibulée. Les notions de double, de miroir, les questions de l’empathie et du rejet, les fantasmes de mort et de torture, s’accrochent à cette mécanique infernale…_”\n\nRosita Boisseau\n\nLe Monde, 8 juillet 2016', 'fr', NULL),
(146794, 'Marpa du Pays d''Urfé ', 'Maintenir dans un environnement connu, à proximité de leurs familles et amis, les personnes âgées du territoire du Pays D’Urfé. ', '## Création d''une MARPA,\n\nRéaménager l''ancienne maison de retraite de ST ROMAIN D''URFE en MARPA (Maison d''Accueil et de Résidence pour l''Autonomie),\n\nOffrir le confort, la liberté de vie d''un logement individuel, la sécurité et la convivialité d''une structure à taille humaine, dans 22 logements (20 T1bis et 2 T2)  adaptés,  tous de plain-pied avec accès privatif,\n\nPermettre à chacun de "vivre comme chez soi" et de profiter pleinement d''une vie associative riche et dynamique au cœur du village dans un environnement de qualité,\n\nAtténuer le sentiment de déracinement,\n\nRépondre aux besoins des personnes à mobilité réduite.\n\n**Plus d''infos :**\n\nhttps://www.helloasso.com/associations/association-pour-la-creation-et-la-gestion-de-la-marpa-du-pays-d-urfe/collectes/marpa-du-pays-d-urfe', 'fr', ',   accueil,  residence,  autonomie'),
(146795, 'Projection du film "L''homme d''à coté, le voisin que Le Corbusier n''avait pas prévu"', 'Un film tourné dans les lieux de la seule oeuvre de Le Corbusier en Amérique Latine : la maison Curutchet.', 'Réalisation : Mariano Cohn et Gastón Duprat - Argentine - 2009 - 110 '' - VOSTF\n\nSynopsis : Leonardo fait partie des designers en vogue de son pays. Signe évident de sa réussite, il vit avec son épouse Ana et sa fille Lola dans la maison Curutchet, seule maison construite par Le Corbusier en Argentine.Un matin, il est réveillé par un bruit obsédant : comme si on perçait un mur…\n\n_« Nous voulions aussi faire [de la maison] un personnage à part entière, et non un simple décor. Il y a beaucoup de scènes où la maison est seule, sans personnage. La plasticité, la lumière et la qualité spatiale de cette maison sont infernales ! »_ Gaston Duprat, réalisateur.\n\n**Soirée partenaire avec la Maison de l''architecture Auvergne**', 'fr', 'Corbusier,    cinéma,    film,    argentine,   humour,  maison Curutchet, Le Corbusier'),
(146796, 'La Fête de la Science à la Cité des Sciences et de l''Industrie', 'Un week-end gratuit de médiations, spectacles, démonstrations, expos, ateliers et rencontres.', 'Venez apprendre à simuler la montée des océans à l’aide d’un bac à sable en réalité augmentée ou écouter le 3D varius, un violon électrique 3D basé sur le modèle d’un véritable Stradivarius.\n\nTestez Birdly un simulateur de vol et devenez le roi des airs ! Les plus jeunes, pourront s’initier à la programmation, participer à des ateliers LEGO®...\n\nProfitez aussi des expositions _Mutations urbaines et_ _Mental désordre_ accessibles gratuitement.\n\n**Nos médiateurs scientifiques les accompagneront et répondront à toutes les questions…**', 'fr', NULL),
(146797, 'SPAT''SONORE', 'Spat''Sonore fait son cirque à l''Atelier du Plateau', 'Avec les circassiens : Katja Andersen, corde lisse et portées, Ricardo Gaiser, acrobatie et portées, Jean-Charles Gaume, fil souple thérapeutique, Lucas Bergandi, fil à grande vitesse, Pauline Barboux et Jeanne Ragu, quadrisse, Malte Peter, jongleur masqué, Martina Covone, corde lisse, Arthur Sidoroff, fil d’argent.\n\nEt les musiciens :\n\nJean-Michel Pupin, voix spatialisée, Thomas Beaudelin, saxophone spatialisé, Nicolas Chedmail, cor spatialisé, Richard Comte, guitare spatialisée.\n\nhttp://www.atelierduplateau.org/agenda/voir/2730', 'fr', NULL),
(146798, 'Installer Wordpress sur son ordinateur', 'Installer Wordpress sur son ordinateur, en local', '## DESCRIPTION\n\nVenez installer le CMS Wordpress, en local, sur votre ordinateur et repartez avec un Wordpress fonctionnel. En installant Wordpress en local, vous pouvez construire votre sitre Web / Blog sur votre ordinateur avant de le mettre en ligne.\n\nAvec cette méthode, vous pourrez aussi gérer plusieurs projets Web et tester vos thèmes, plugins, css... avant de les mettre en production.\n\nSujets abordés :\n\n- Notion de serveur (php, mysql)- Notion de base de données\n\n- Installation d''un serveur local- Création d''une base de données\n\n- Installation de Wordpress\n\n- Premiers réglages de Wordpress \n\n**FAQ **\n\nQue dois-je apporter le jour de l''atelier ?\n\nUn ordinateur portable PC ou MAC\n\nComment puis-je contacter l''organisateur en cas de question ?\n\npar mail à [epn@ageca.org](mailto:epn@ageca.org)\n\nVais-je apprendre à utiliser Wordpress ?\n\nNon, ce workshop concerne l''installation de Wordpress et non son utilisation. Vous pourrez participer par la suite à nos ateliers Wordpresss.\n\n[![Eventbrite - Installer Wordpress sur son ordinateur](https://www.eventbrite.fr/custombutton?eid=28426592704)](http://www.eventbrite.fr/e/billets-installer-wordpress-sur-son-ordinateur-28426592704?ref=ebtnebregn)', 'fr', 'wordpress, cms'),
(146799, 'Festival Sciences en vues', 'La salle Louis Lumière et la bibliothèque de la cité accueillent une partie de la programmation du Festival Pariscience ', '**Des projections thématiques de films pour petits et grands :**\n\n- Des rencontres avec des concepteurs et des producteurs de webdocs et de serious games\n\n- Des multimédias en libre consultation\n\n- Deux projections-débats autour des films « La sociologue et l’ourson », samedi 8 octobre à 17h et « Peau d’âme », dimanche 9 octobre à 17h', 'fr', 'Cinéma'),
(146800, 'Le Palais de la Découverte fête la science', 'Pour découvrir de façon simple les diférentes facettes scientifiques des choses et évènements qui nous entourent.', 'L’accent est mis sur un accès universel et concret aux sciences et techniques, par le biais d''exposés, d''expériences  et de rencontres avec des médiateurs... tous passionnés et investis dans ce projet commun : transmettre le goût pour les sciences.', 'fr', NULL),
