INSERT INTO `${schema}` (`id`, `title`, `description`, `free_text`, `lang`, `tags`) VALUES
(146815, 'Multiplex inter Nuit(s) Debout', 'Tentons une assemblée NuitDebout nationale', 'Nuit Debout, on l''oublie souvent, est un mouvement d''envergure nationale, qui implique de nombreuses villes et places en France (et parfois ailleurs).\n\nIl fait donc face à d**''importants besoins de coordination** au niveau national.\n\nDe nombreux participants au mouvement, à Paris, à Lyon, à Rennes, à Poitiers, partout, ont élaboré différents moyens de communication et d''interconnexion entre ces initiatives locales :\n\n- Réunions physiques, à Notre-Dame-des-Landes ou Paimpont\n\n- Bulloteries\n\n- Outils numériques existants (listes riseup, numéro de téléphone "public") ou en construction \n\nSurtout, un rendez-vous a été pris pour organiser de manière régulière un multiplex audio entre toutes les Nuit Debout - accessible à tous - afin de mieux partager ses démarches, et mieux s''accorder sur les projets à venir.\n\nNous vous invitons donc à venir en discuter le 7 octobre en multiplex inter-villes.\n\nNote aux participants des Nuit Debout :\n\nN''hésitez pas à faire circuler cet évènement autour de vous - et notamment aux autres Nuit Debout avec lesquellles vous êtes en contact.\n\nLe lien pour vous y retrouver facilement :  [http://www.espacevocal-nuitdebout.fr/](http://www.espacevocal-nuitdebout.fr/)\n\nMerci\n\nSolidairement', 'fr', 'multiplex, Mumble, National, Coordination'),
(146816, 'Soirée Concert débat avec Claude Antonini', 'les chansons engagées et la censure d''hier à aujourd''hui', 'la  Société des Amis de l''Humanité du Loiret vous invite à une soirée concert débat avec **Claude Antonini et au piano Vincent Viala**\n\nsur le thème :  les chansons engagées et la censure d''hier à  aujourd''hui\n\n**le vendredi 04 novembre 2016 à l''auditorium Marcel Reggui. **', 'fr', ', Claude Antonini'),
(146817, 'Le financement de l’entreprise :  Comment s’y retrouver ?', 'Conférence suivie d’un cocktail organisée par le Boss Club PME, le Challenger Club, So Digital et Meudon Valley', 'Lorsqu’on vous parle de financement des entreprises, vous pensez :\n\n*   On n’y comprend rien\n*   On ne s’y retrouve pas\n*   Cela ne vaut pas la peine d’essayer, on n’y croit plus\n*   Rien de neuf sur le sujet…\n\nAutant d’idées reçues ou préconçues que nous allons bousculer lors de cette conférence. Que vous soyez porteur de projet, start up ou dans une phase de développement de votre entreprise, vous repartirez mieux éclairés avec un guide d’orientation en poche.\n\n**Intervenants :**\n\n*   Géraldine BELLANGER – Banque Populaire,\n*   Jallil YAKER (BPI),\n*   Christophe MORAS (Seine Ouest Entreprise et Emploi),\n*   Paul FROMENT (DL Développement),\n*   Thierry LEGRAND et Hervé COLSON (EXPONENS),\n*   un représentant de la CCI 92\n\nUn cocktail sera servi vers 20h30 pour continuer les échanges avec les intervenants, moment également propice au réseautage.\n\nPour nous permettre de préparer au mieux cette conférence, merci de nous adresser vos questions sur le financement par e-mail à [contact-evenements@boss-club.net](http://mailto:contact-evenements@boss-club.net) avant le 10 novembre.', 'fr', 'startup, financement'),
(146818, 'Dressuurwedstrijd pony', 'Dressuurwedstrijd pony', '', 'nl', ''),
(146819, 'Journée Portes Ouvertes', 'Journée d''information et d''orientation', 'Venez nous rencontrer à l''occasion de la 1ière Journée Portes Ouvertes de l''Année 2016/2017.\n\nLes Journées Portes Ouvertes sont des rendez-vous privilégiés vous permettant de :\n\n-découvrir le cursus Epitech,\n\n-visiter les locaux,\n\n-échanger avec les étudiants, les encadrants pédagogiques, et les membres de l''administration.\n\nMais c''est aussi pour vous l''occasion de poser toutes les questions que vous pouvez vous poser sur :\n\n-les débouchés,\n\n-les conditions d''admission,\n\n-les moyens de financer vos études.\n\nEn parallèle, découvrez le code lors d''un atelier animé par nos Cobras de 14h à 17h:\n\nInscription sur codingclub.epitech.eu\n\nAdresse : 5-9 Rue du Palais Rihour, 59000 Lille\n\nTéléphone : 01 44 08 00 10', 'fr', NULL),
(146820, 'Village des sciences de Montpellier - Jardin des plantes', 'Se laisser tenter par une balade au Village des sciences de Montpellier c’est à coup sûr une belle opportunité pour découvrir, expérimenter, échanger et questionner des chercheurs !', 'Se laisser tenter par une balade au Village des sciences de Montpellier c’est à coup sûr une belle opportunité pour découvrir, expérimenter, échanger et questionner des chercheurs ! C’est aussi tout un programme ponctué d’animations : démonstrations, expérimentations, projections, conférences, spectacles, jeux, … pour petits et grands. Ce "village de toutes les sciences" se déploie sur deux lieux montpelliérains emblématiques : la Faculté de médecine et le Jardin des plantes de l’Université de Montpellier. Passionnés de sciences ou simples curieux, en famille ou entre amis, le Village des sciences de Montpellier est un événement à ne pas manquer !\n\nVendredi 14 octobre (réservé aux scolaires) Samedi 15 & dimanche 16 octobre (tout public)\n\nTout le programme du village à télécharger sur :\n\n[https://cs.umontpellier.fr/wp-content/uploads/2016/09/Programme_FDS_2016.pdf](https://cs.umontpellier.fr/wp-content/uploads/2016/09/Programme_FDS_2016.pdf)', 'fr', NULL),
(146821, 'Invité des "Lundis de la primaire" dans la matinale d''Europe 1, entre 7h30 et 9 heures.', 'François Fillon est l''invité des "Lundis de la primaire" dans la matinale d''Europe 1, entre 7h30 et 9 heures.', NULL, 'fr', NULL),
(146822, 'Visite architecturale "Cathédrale de Créteil"', 'Une coupole de bois de 22 mètres de haut , un clocher à la silhouette élancée : la cathédrale de Créteil de 2015 est plus visible, plus vaste et plus lumineuse que celle d''origine.', 'L''Agence Architecture Studio avait pour mission de doubler la capacité d''accueil de la cathédrale sans pourtant accroître les dimensions au sol du bâtiment d''origine, édifié par Charles-Gustave Stoskopf en 1978\\. En proposant cette métamorphose, l''agence d''architecture souhaitait questionner la notion du symbole en architecture, ou matière et lumière donne une dimension nouvelle à ce bâtiment, inscrit dans le temps.\n\nÀ l''occasion des Journées Nationales de l''Architecture, venez découvrir ou redécouvrir cette cathédrale du XXIème siècle !\n\nVisite guidée par Mikaël GOBIN, architecte au CAUE du Val-de-Marne, et Marie-Pierre ETIENNEY, responsable des projets immobiliers au diocèse de Créteil et coordinatrice du projet de redéploiement de la cathédrale.', 'fr', ',        cathédrale,        extension,       bois,     lumière,    symbole,   architecture,  créteil, culte'),
(146823, 'Village des sciences de Montpellier -Faculté de médecine', 'Se laisser tenter par une balade au Village des sciences de Montpellier c’est à coup sûr une belle opportunité pour découvrir, expérimenter, échanger et questionner des chercheurs ! ', 'Se laisser tenter par une balade au Village des sciences de Montpellier c’est à coup sûr une belle opportunité pour découvrir, expérimenter, échanger et questionner des chercheurs ! C’est aussi tout un programme ponctué d’animations : démonstrations, expérimentations, projections, conférences, spectacles, jeux, … pour petits et grands. Ce "village de toutes les sciences"se déploie sur deux lieux montpelliérains emblématiques : la Faculté de médecine et le Jardin des plantes de l’Université de Montpellier. Passionnés de sciences ou simples curieux, en famille ou entre amis, le Village des sciences de Montpellier est un événement à ne pas manquer !\n\nVendredi 14 octobre (réservé aux scolaires)Samedi 15 & dimanche 16 octobre (tout public)\n\nTout le programme du village téléchargeable sur : \n\n[https://cs.umontpellier.fr/wp-content/uploads/2016/09/Programme_FDS_2016.pdf](https://cs.umontpellier.fr/wp-content/uploads/2016/09/Programme_FDS_2016.pdf)', 'fr', NULL),
(146824, 'Exposition "Les Bains Municipaux de Châlons en Champagne"', 'Exposition d''archives, objets, documents architecturaux et projets d''études', 'Anciens Bains municipaux, présentés par leur histoire, leur évolution, leur état actuel et leur possible devenir.\n\nArchives journalistiques, photographiques, objets et traces du passé\n\nPlans, maquettes et vues d''un état des lieux et de possibles devenirs par le projet de diplômes de fin d''étude d''architectes sur ce site.', 'fr', ',    exposition,   bains municipaux,  diplôme, archives'),
(146825, 'Contrebrassens à Paris (19ème)', 'Sortie du deuxième album', 'Une femme, une contrebasse :  \nUn ménage à deux qui révèle toute la saveur musicale des mélodies,  \nla finesse des textes et nous fait redécouvrir Brassens.  \nPromenade dans des histoires choisies autour de la femme.\n\nAvec : Pauline Dupuy (contrebasse) et Michael Wookey (guitare)\n\n[https://www.youtube.com/watch?v=xEN973TUjNQ](https://www.youtube.com/watch?v=xEN973TUjNQ)', 'fr', 'Concert, Brassens, Contrebrasse, Chanson'),
(146826, 'Tournoi inter-secteur du Fenix', 'organisation d''un tournoi -11 ans des différents secteur de Toulouse', 'les 80 enfants de -11 du Fenix se connaissent très peu due à la sectorisation de la pratique. Il n''y a pas encore eu de moment pour sensibiliser joueurs,les entraîneurs et parents aux habitus de santé que nous préconisons au Fenix.\n\nCe tournoi sera l''occasion d''allier le plaisir de se connaître et partager la même passion mais également d''acquérir des savoir-faire et des savoir-être autour de la prévention (échauffements, étirements...) et de la nutrition (repas d''avant match, goûter d''après match...)\n\nLors de se tournoi, les équipes de secteur seront mélangées; parents et entraîneurs seront en charge de l''organisation sportive mais aussi du goûter. \n\nLe menu du midi sera conçu par la diététicienne partenaire du club professionnel', 'fr', ',    Respect,   Partage,  Prévention, Nutrition'),
(146827, 'SOIRÉE LANGUE DES SIGNES - spéciale Elix', 'Elix, le dictionnaire vivant en langue des signes fait peau neuve !  Venez tester le nouveau site avant sa mise en ligne ! ', '## **SOIRÉE LANGUE DES SIGNES**\n\nJEUDI 13 OCTOBRE / 18H30\n\nLILLE\n\nGRATUIT / OUVERT À TOUS\n\nPrésence d’une interprète en LSF\n\nElix, le dictionnaire vivant en langue des signes fait peau neuve !\n\nNous organisons une soirée pour fêter cet événement.\n\nVenez tester le nouveau site avant sa mise en ligne !\n\n### Au programme :\n\n**• PRÉSENTATION EN AVANT-PREMIÈRE DU NOUVEAU SITE**\n\n**• TESTS DU NOUVEAU SITE**\n\nTestez le nouveau site avant tout le monde ! Et faites-nous part de vos avis, remarques..\n\n**• MARATHON DU SIGNE**\n\nVenez compléter en direct le dictionnaire avec les signes que vous connaissez.\n\n**• FABRIQUE DE BADGES PERSONNALISÉS**\n\nRepartez avec votre badge personnalisé aux couleurs de Elix.\n\nLe tout dans une ambiance conviviale :D VENEZ NOMBREUX !\n\n_____________________________________________\n\n### Elix en quelques mots :\n\nAvec plus de 13 000 signes et 10 000 définitions traduites en langue des signes, Elix est la plus grande ressource en LSF.\n\nElix est consultable gratuitement sur internet www.elix-lsf.fr et sur smartphones et tablettes grâce aux applications disponibles sur l’Appstore et Google Play.\n\n_____________________________________________\n\n### Infos pratiques :\n\nMutualab 19 rue Nicolas Leblanc Lille\n\nAccès Métro : Ligne 1 – Arrêt République Beaux-Arts', 'fr', 'Elix, langue des signes, lsf'),
(146828, 'L''improbable Duo à Nantes (44)', 'Contrebrassens et Michael Wookey', 'Contrebrassens & Michael Wookey : l''improbable duo.\n\nL’univers pop et décalé du british singer songwriter Michael Wookey croise les interprétations féminines de Georges Brassens par la contrebassiste et chanteuse Pauline Dupuy.\n\nDeux personnalités vivantes et complices qui nous touchent par leur authenticité et la qualité de leurs interprétations. Un concert vibrant, généreux et coloré.\n\nhttps://www.youtube.com/watch?v=jSgZ-yw1CaI', 'fr', 'Concert, Brassens, Contrebrasse, Chanson'),
(146829, 'Visites guidées Marché Victor Hugo', 'Visites guidées Marché-Parking Victor Hugo à Toulouse - les samedi 15 et dimanche 16.10.2016 à 10h30', 'À l’occasion de l’anniversaire du Marché-Parking Victor Hugo, découvrez l’histoire de ce lieu et venez rencontrer la Maison de l’Architecture dans la loge-info du marché qui sera ouverte de 8h à 13h.\n\nCette installation vous est proposée par la Maison de l''Architecture Midi-Pyrénées et Toulouse Métropole avec la collaboration des Archives Municipales et de l''association des commerçants du marché Victor Hugo.\n\nProfitez des deux visites événementielles commentées par un architecte; elles vous transporteront dans l''histoire de ce bâtiment emblématique de l''architecture moderne à Toulouse.\n\nCrédit photo : Philippe Ruault', 'fr', 'visites-guidées,   architecture,   toulouse,  marché'),
(146830, 'L''improbable Duo à Fougères (35)', 'Contrebrassens et Michael Wookey', 'Contrebrassens & Michael Wookey : l''improbable duo.\n\nL’univers pop et décalé du british singer songwriter Michael Wookey croise les interprétations féminines de Georges Brassens par la contrebassiste et chanteuse Pauline Dupuy.\n\nDeux personnalités vivantes et complices qui nous touchent par leur authenticité et la qualité de leurs interprétations. Un concert vibrant, généreux et coloré.\n\nhttps://www.youtube.com/watch?v=jSgZ-yw1CaI', 'fr', 'Concert, Brassens, Contrebrasse, Chanson'),
