(147110, 'LA VILLE D''ART ET D''HISTOIRE DE BASSE-TERRE : visite-guidée du Palais du Conseil Départemental', 'Palais du Conseil Départemental est une architecture moderniste des années 30 par l''architecte Ali Tur', 'Dotée de nombreuses constructions signées de l’architecte Ali TUR, Basse-Terre peut s’enorgueillir de trois palais majeurs sur son territoire, du fait de sa vocation de chef-lieu : le Palais du Conseil Départemental, le Palais de Justice et le Palais du Gouverneur (Préfecture). Ces constructions représentent, avec une belle unité, l’architecture moderniste (années 30) aux Antilles.\n\nVous pourrez apprendre à vous familiariser avec l’œuvre du bâtisseur, son style, et le contexte dans lequel il est intervenu.', 'fr', 'architecture moderniste, Ali Tur, années 30, béton armé, batiment public'),
(147111, 'Visite architecturale du "Palais du Conseil Départemental"', 'Palais du Conseil Départemental est une architecture moderniste des années 30 par l''architecte Ali Tur', 'Dotée de nombreuses constructions signées de l’architecte Ali TUR, Basse-Terre peut s’enorgueillir de trois palais majeurs sur son territoire, du fait de sa vocation de chef-lieu : le Palais du Conseil Départemental, le Palais de Justice et le Palais du Gouverneur (Préfecture). Ces constructions représentent, avec une belle unité, l’architecture moderniste (années 30) aux Antilles.\n\nVous pourrez apprendre à vous familiariser avec l’œuvre du bâtisseur, son style, et le contexte dans lequel il est intervenu.', 'fr', 'architecture moderniste, Ali Tur, années 30, béton armé, batiment public'),
(147112, 'Animation découverte Gyropode', 'Venez vous initier au gyropode sur un parcours balisé.  5 véhicules sont mis à votre disposition pour des essais gratuits et de l''information. Des casques vous seront fournis. ', NULL, 'fr', NULL);
INSERT INTO `${schema}` (`id`, `title`, `description`, `free_text`, `lang`, `tags`) VALUES
(147113, 'RANDO ROLLERS', 'Le service municipal de la jeunesse vous propose de venir découvrir ou redécouvrir, dans une ambiance festive, à rollers, à trottinettes ou à vélo les voies de circulation douces de la commune.', 'Le service municipal de la jeunesse vous propose de venir découvrir ou redécouvrir, dans une ambiance festive, à rollers, à trottinettes ou à vélo les voies de circulation douces de la commune. Un circuit du parking de la mairie jusqu’à la coulée douce de Villejust vous sera proposé.\n\nUne collation (thé, café, petits gâteaux...) sera offerte à l’issue de la randonnée.\n\nTout public.\n\nVendredi 14 octobre, départ à 20h, parking de la mairie', 'fr', NULL),
(147114, 'Tournoi 4*4 handball', 'Tournoi 4*4  mixte ', 'Incitation  à participer aux tournois  handball 4*4 auprès des associations sportives dans les 3 départements de l académie de Créteil', 'fr', NULL),
(147115, 'Activités de sensibilisation à l''architecture et projection pop''up bus!', 'l''association Graines d''archi propose différentes activités ludiques de sensibilisation à l''architecture et une projection de films', '**Ateliers**\n\n1\\. Réalisation de cartes sensibles : observer son environnement, comprendre l’espace urbain, le représenter et s’approprier l’outil « dessin », déchiffrer les éléments mis en valeur par le dessin ainsi réalisé...\n\n2\\. Jeux dans l’espace : dessins à taille réelle à la craie sur le sol, observation des effets produits par ces dessins sur les cheminements des passants, apprendre à mesurer (nombre de pas, de mains...) / construction avec des modules en cartons (sa cabane en carton, un igloo, un mur, une porte...)\n\n3\\. Parcours les yeux bandés en binôme, pouvant se faire à l’occasion dans les constructions de carton, et représentation en dessin de l’expérience vécue, des sensations éprouvées...\n\n**Projection de Films**\n\nLa galerie propose en partenariat avec les étudiants de l''école d''architecture de Marseille et l''association Graines d''archi une projection de films avec le pop''up bus sur l''analyse de bâtiments de la région réalisés par les étudiants:\n\n1/ L’Eglise et la Maison de Jeunes de la Pauline\n\nArchitecte : Pierre Averous /1961-1962\n\nCentre religieux et maison des jeunes\n\nCité « la Pauline » boulevard Romain Rolland 13009 Marseille.\n\n2/ Groupe scolaire Paul Cézanne\n\nArchitectes : Jean-Marc Chancel, J.S Cardone /2013-2014\n\nEcole maternelle et Ecole élémentaire\n\nSalles de classe, restauration, salle d’évolution sportive et piscine.\n\nQuartier de la Maille 2, Miramas\n\n3/ Résidence Tourisme Parc habité\n\nArchitectes :Stéphane Fernandez, Ivry Serre /2012\n\nLogements, résidences temporaires\n\n215 studios en résidence tourisme,\n\nlocaux activités, commerces, cafétéria, parking\n\n(Immeuble Villa Appart-city )\n\n130, rue Ruffi Marseille 13003\n\n4/ Le centre régional d’Information\n\net de Coordination routière\n\nArchitecte : Rudy Ricciotti /1990-1992\n\nBureaux des services de l’Equipement, de la gendarmerie et de la police, circulation routière\n\n62, boulevard Icard (13010).\n\n5/ Le Saint Georges\n\nArchitecte : Claude Gros /1960-1963\n\nensemble de logements et équipements, église.\n\nplace du Quatre Septembre, 13007 Marseille\n\n6/ FRAC Provence Alpes Côte d’azur\n\nArchitecte : Kengo Kuma /ouverture 2013\n\n(Fond régional d’Art Contemporain)\n\nCe bâtiment a pour vocation la constitution et la diffusion d’une collection d’Art contemporain, la programmation et la réalisation d’expositions temporaires,\n\nprogramme de rencontres, conférences, éditions\n\n5 400 m2\\. Ouverture :\n\n20, bd de Dunkerque, angle des rues\n\nVincent Leblanc et Forbin, Marseille.\n\n7/ Stadium de Vitrolles\n\nArchitecte : Rudy Riccioti /1994\n\nsalle de concert et évènement sportif de haut niveau,\n\ncapacité 5000 places, inauguré en 1994\\. Vitrolles\n\n8/ Pavillon noir\n\nArchitecte : Rudy Riccioti /2004-2006\n\nsalle de spectacle, accueil du ballet Preljocaj, 300\n\n530 av Mozart, Aix en Provence.', 'fr', 'ateliers,  jeux,  cartes sensibles,  architecture, films'),
(147116, 'Hand-Ball pour tous', 'ASSOCIATION SPORTIVE DU COLLEGE MARGUERITE DURAS', 'L''AS Hand-Ball du clg M. DURAS permet à de nombreux élèves de découvrir ou d''approfondir leurs connaissances du hand-ball.\n\nCette AS est un véritable tremplin pour ces élèves issus de quartiers socialement défavorisés. Depuis déjà de nombreuses années, plusieurs élèves ont intégré le club de Hand-Ball de la ville de Colombes et développent leur pratique dans le milieu fédéral.', 'fr', ',    AS,    DURAS,   HANDBALL, COLOMBES'),
(147117, 'Midi Minuit Montreuil', 'Midi, Minuit, Montreuil (#MMM) vous donne rendez vous pour des évènements ou musique et culture urbaine se rencontrent dans des lieux atypiques.', 'Le "Midi, Minuit, Montreuil" (#MMM) vous donne rendez-vous pour des événements originaux où musique et culture urbaine se rencontrent dans des lieux atypiques!\n\nAu programme :• Line Up pointus de Groove, Deep-house, Techno...• "Art"istes &"Art"isans• Cocktail Bar & Food Corner • ...\n\nLe "Midi Minuit Montreuil" by TaKoTaKDimanche 16 octobre 2016 au 19 de la rue Girard à Montreuil(Ligne 9, station Croix de Chavaux, sortie Place du Marché)\n\n#MMM ou comment vivre la fête autrement!_____________________________________________________\n\n* LINE UP *\n\n• Label 90bis records- Claire - Rec - Hisham (live) - Milan Seguin- Chicago 5000 - 90bis records• Mndll B2B art hur• Dick Sant\n\n* ART''istes *\n\n• Performeur• Graffeur TEMA & VORE• Photographe• Peintre MARTIALSamuel Artiste\n\n* ART''isans *\n\n• Cocktail Bar • Food Corner\n\nLa Petite DéMesure', 'fr', ',      event,     musique,    culture,   urbain,  montreuil, art'),
(147118, 'Kaggle #7', 'Partager et échanger sur les concours de data science du moment', 'Pour commencer la saison, nous vous proposons de pencher sur le concours du Meilleur Data Scientist de France.\n\nLa première édition de ce challenge éclair, organisé par FrenchData, a réuni au cours d’une soirée 250 passionnés de data. Ce challenge est désormais ouvert à tous. Le thème était : combien coûte une boite de médicament ?  L’objectif de ce challenge est de mettre au point un modèle prédictif pour estimer combien coûte une boite de médicament, afin par exemple d’aider à en fixer le prix, ou bien détecter des anomalies dans les tarifs.\n\nEn attendant le jour J, n''hésitez pas à :\n\n•  Télécharger et regarder les données avant de venir\n\n• Vous connecter sur le slack du TDS ou utiliser la mailing list pour nous dire où vous en êtes ! \n\n----------------------------------------------------------------------------------------\n\nPré-requis :\n\nLors de cette rencontre, vous devez être muni d’un ordinateur portable relativement récent et avoir installé \n\n• Anaconda : distribution Python (version 2.7) libre intégrant directement un grand nombre de packages pour la Data Science.\n\nhttps://www.continuum.io/downloads\n\n• Un éditeur tel que Jupyter Notebook (ou Zeppelin, IPython) est également à prévoir (déjà installé dans Anaconda)\n\nhttp://jupyter.readthedocs.io/en/latest/install.html\n\n----------------------------------------------------------------------------------------\n\n**L’objectif des meet-up Kaggle est de fédérer une communauté de personnes, souhaitant découvrir et partager les meilleures recettes à utiliser dans les compétitions de Machine Learning organisées par les plate-formes  Kaggle ou datascience (feature engineering, hyper paramètres, cross validation, stacking, ensemble, blending, ''eXtreme Gradient Boosting'', etc).**', 'en', 'Data Science, TDS, Kaggle,  Machine Learning'),
(147119, 'Atelier jeunesse', 'Un atelier photo pour les jeunes', '(**PROJET** : dates et modalités peuvent être modifiées)\n\nPar la réalisation de projets en commun ou de projets individuels, les jeunes découvrent la photo, ses fondements techniques, son histoire, son rôle social, son esthétique, sa teneur artistique. Il est ludique sans être récréatif.\n\nMatériel à posséder pour participer à l''atelier : un appareil de prise de vues quel qu''il soit (tablette, téléphone, compact, appareil reflex, bridge etc.).\n\nAnimé par un(e) photographe ayant une bonne formation de départ et engagé(e) dans une démarche de création. L''animateur possèdera la liberté de mener son projet comme il le souhaite.\n\nJeunes de 8 à 12 ans.\n\nminimum 6 - maxi 10.\n\nParticipation à l''atelier : 80 euros', 'fr', NULL),
(147120, 'Atelier jeunesse', 'Un atelier photo pour les jeunes', '(**PROJET** : dates et modalités peuvent être modifiées)\n\nPar la réalisation de projets en commun ou de projets individuels, les jeunes découvrent la photo, ses fondements techniques, son histoire, son rôle social, son esthétique, sa teneur artistique. Il est ludique sans être récréatif.\n\nMatériel à posséder pour participer à l''atelier : un appareil de prise de vues quel qu''il soit (tablette, téléphone, compact, appareil reflex, bridge etc.).\n\nAnimé par un(e) photographe ayant une bonne formation de départ et engagé(e) dans une démarche de création. L''animateur possèdera la liberté de mener son projet comme il le souhaite.\n\nJeunes de 8 à 12 ans.\n\nminimum 6 - maxi 10.\n\nParticipation à l''atelier : 80 euros', 'fr', NULL),
(147121, 'Rencontre-débat', 'Participer à un concours, céder ses photos', 'Un amateur a envie de montrer ses photos. Les sollicitations sont nombreuses : concours, proposition d''expositions, propositions d''édition. Quels sont les pièges à éviter ? Comment se faire respecter ? Quel est l''intérêt de ces publications ? Un amateur peut-il vendre ses photos ?\n\nUne rencontre où nous ferons le point sur la législation et nous débattrons de ces questions.', 'fr', NULL),
(147122, 'Atelier de web Design', 'Tout ce que vous avez toujours voulu savoir sur le web design ... sans jamais oser le demander', 'Webdesign, UI, mobil first, UX - si ces mots vous semblent ésotériques, mais que vous les entendez parfois, alors les ateliers du Web Design sont là pour vous ! Au travers d’expériences de professionnels, ces ateliers ont pour objectifs de vous présenter clairement et pratiquement ce qui se cache derrière ces vocabulaires, mais aussi et surtout les tendances du web qu’ils représentent.\n\nLes Ateliers du Web Design sont des événements mensuels pour promouvoir la veille, la rencontre et le partage entre apprentis ou professionnels du webdesign.\n\nUne fois par mois, des intervenants animeront un atelier sur l’une des nombreuses thématiques liées au web design, de la représentation graphique du besoin d’un client à son intégration technique.\n\nLe temps d’une soirée, venez échanger des méthodes et des outils, puis partager vos connaissances avec d’autres membres de la communauté numérique de la région - étudiants, professionnels ou autodidactes - dans une ambiance conviviale et décontractée.\n\nLes sujets abordés durant cette première saison iront de questions législatives et d’accessibilité, à la conception de mock-up et de l’expérience utilisateur, jusqu’à la mise en place technique du projet qu’elle soit pensée “App First” ou encore avec un framework.\n\nRetrouvez la liste complète des thématiques pour 2016/2017 ci-dessous :\n\n2016\n\n  Octobre - Veilles et tendances (outils, sites à consulter…) - Marie Cottu & Christèle Maitre\n\n Novembre - App First => de l’application au Desktop - Android - Peter Bardu\n\n Décembre - App First => de l’application au Desktop - IOS - Mathieu Bolard\n\n2017\n\n Janvier - Atelier spécial UI / UX - Manyssin Thin\n\n Février - Sketch / Invision (les mockups) - Arnaud Delpit\n\n Mars - Design Thinking - Cédric Neige\n\n Avril - L’accessibilité dans le web - Ludovic Evelin\n\n Mai - Framework - bootstrap, foundation - Olivier Plessis\n\n Juin - Animations HTML JS CSS3 - Benoits Lawniczak\n\n Juillet - Atelier optimisation des pages web (sass, less, taille des images)\n\n Septembre - SEO : webdesign & micro-data - Laure Ricote\n\n Octobre - Le droit dans le web - Valérie Leperlier-Roy\n\nLes ateliers sont gratuits et ouverts à tous. Des compétences en web sont néanmoins requises pour faciliter les échanges.', 'fr', ', web design'),
